INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('149200000026', '국민내일배움카드', JSON '{"서비스ID": "149200000026", "서비스명": "국민내일배움카드", "서비스목적요약": "직업훈련을 희망하는 국민에게 직업능력개발훈련비와 훈련장려금 지원", "지원내용": "○ 5년간 300~500만원 한도 내에서고용노동부로부터 인정받은 적합훈련과정을 수강하는 경우\r\n    훈련비의 일부 또는 전액을 지원", "지원대상": "○ 국민 누구나\r\n\r\n○ 지원 제외 대상\r\n ① 공무원, 사립학교 교직원\r\n ② 졸업까지 수업연한이 2년이 초과하여 남은 대학생 및 졸업예정자가 아닌 고등학생\r\n ③ 연 매출 4억원 이상의 자영업자 \r\n ④ 월 임금 300만원 이상인 대규모기업 근로자(만 45세 미만)\r\n ⑤ 월 소득 500만원 이상인 특수형태근로종사자 등\r\n ⑥ 만 75세 이상자 등", "소관기관명": "고용노동부", "서비스분야": "고용·창업", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/149200000026", "지원유형": "서비스(일자리)"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('149200005007', '국민취업지원제도', JSON '{"서비스ID": "149200005007", "서비스명": "국민취업지원제도", "서비스목적요약": "직업훈련, 일경험, 복지 프로그램 연계 등 취업지원서비스 제공 및 생계안정 지원", "지원내용": "ㅇ 취업취약계층(저소득층, 청년, 경력단절여성 등)에게 맞춤형 취업지원서비스를 제공하고, 저소득 구직자에게는 생계안정을 위한 소득도 함께 지원\r\n\r\nㅇ 지원내용\r\n  -  취업지원(I,II유형 공통): 심층상담을 통해 개인별 역량, 의지에 따른 직업훈련, 일경험, 복지 프로그램 연계 등 취업지원서비스 제공\r\n  -  소득지원(I유형): 구직활동 이행시 구직촉진수당(월 60~100만원, 6개월) 지원\r\n  -  취업활동비용지원(II유형): 취업활동계획 수립 참여수당 등", "지원대상": "∙ I유형\r\n  -(요건심사형) 15세~69세 구직자 중 중위소득 60% 이하, 재산 4억 이하(15~34세 청년은 재산 5억원 이하)이면서, 최근 2년 이내 100일 또는 800시간 이상의 취업경험이 있는 분\r\n  -(선발형) 15세~69세 구직자 중 요건심사형 중 취업경험 요건을 충족하지 못한 분( 15~34세 청년은 중위소득 120% 이하, 재산 5억원 이하, 취업경험은 선발시 고려)\r\n\r\n∙ II유형: 15세~69세 구직자 중 I유형에 해당하지 않는 가구단위 중위소득 100% 이하(청년은 소득 무관)", "소관기관명": "고용노동부", "서비스분야": "고용·창업", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/149200005007", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('135200005003', '긴급복지 생계지원', JSON '{"서비스ID": "135200005003", "서비스명": "긴급복지 생계지원", "서비스목적요약": "식료품비, 의복비 등 생계유지에 필요한 비용 지원(최대 6개월) ", "지원내용": "○ 지원대상 : 위기상황에 처한 사람으로 소득기준 및 재산기준을 충족하는 사람\r\n○ 지원내용 :  식료품비, 의복비, 냉방비 등 생계유지에 필요한 비용 또는 현물 지원\r\n○ 지원방법 및 기준 : 가구구성원수에 따라 금전 지급\r\n - 1인 가구: 783,000원\r\n - 2인 가구: 1,286,600원\r\n - 3인 가구: 1,644,000원\r\n - 4인 가구: 1,994,600원\r\n - 5인 가구: 2,324,400원\r\n - 6인 가구: 2,636,700원\r\n\r\n*가구구성원이 7인 이상인 경우, 1인 증가 시마다 286,900원씩 추가", "지원대상": "○ 긴급복지지원법 제2조 각 호의 어느 하나에 해당하는 사유로 생계유지가 곤란한 사람\r\n\r\n<위기사유>\r\n1. 주소득자(主所得者)가 사망, 가출, 행방불명, 구금시설에 수용되는 등의 사유로 소득을 상실한 경우\r\n2. 중한 질병 또는 부상을 당한 경우\r\n3. 가구구성원으로부터 방임(放任) 또는 유기(遺棄)되거나 학대 등을 당한 경우\r\n4. 가정폭력 또는 가구구성원으로부터 성폭력을 당한 경우\r\n5. 화재 또는 자연재해 등으로 인하여 거주하는 주택 또는 건물에서 생활하기 곤란한 경우\r\n6. 주소득자 또는 부소득자의 휴업, 폐업 또는 사업...", "소관기관명": "보건복지부", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/135200005003", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('SD0000015536', '구직급여', JSON '{"서비스ID": "SD0000015536", "서비스명": "구직급여", "서비스목적요약": "비자발적으로 이직한 고용보험 피보험자에게 120~270일간 구직급여 지급", "지원내용": "○ 구직급여 : 이직일의 다음 날부터 12개월(수급기간) 내에서, 피보험기간과 연령에 따라 120일-270일간 이직 전 3개월간 평균임금의 60%*를 구직급여 지급\r\n  * 예술인, 노무제공자는 이직 전 12개월간 평균보수의 60%\r\n\r\n○ 개별연장급여 : 구직급여의 70%를 60일간 연장하여 지원\r\n\r\n○ 훈련연장급여 : 구직급여의 100%를 최대 2년간 연장하여 지원\r\n\r\n○ 특별연장급여 : 구직급여의 70%를 60일간 연장하여 지원", "지원대상": "○ 구직급여: 고용보험 적용 사업장에서 경영상 해고 등 비자발적으로 이직한 피보험자로서, 이직일 이전 18개월간 피보험 단위기간 180일 이상* 근무하고, 근로의 의사와 능력이 있음에도 불구하고 실업한 상태에서 적극적으로 재취업 활동을 하는 사람(일용근로자의 경우 수급자격 인정신청일이 속한 달의 직전 달 초일부터 수급자격 인정신청일까지의 근로일 수의 합이 같은 기간 동안의 총 일수의 3분의 1 미만일 것)\r\n\r\n * (예술인) 이직일 이전 24개월간 피보험단위기간 9개월 이상(예술인으로서 3개월 이상)\r\n    (노무제공자) 이직일...", "소관기관명": "고용노동부", "서비스분야": "고용·창업", "신청기한": "이직 후 지체없이 신청(이직일 다음 날부터 12개월 내 본인의 소정급여일수 한도로 지급)", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/SD0000015536", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('B55201500004', '실업크레딧 지원', JSON '{"서비스ID": "B55201500004", "서비스명": "실업크레딧 지원", "서비스목적요약": "구직급여 수급자가 실직기간에도 국민연금 보험료 납부를 희망할 경우 보험료의 75%를 지원", "지원내용": "○ 인정소득은 실직 전 3개월간 평균소득의 50%(최대70만원)로, 지원기간은 구직급여 수급기간으로하되 실업-재취업 반복시 지속수급이 가능하며 생애 최대 12개월까지 지원 받을 수 있음 \r\n\r\n○ 월보험료의 25%를 본인이 부담하는 경우에 한해 연금보험료의 75%를 지원하여 가입기간을 추가 산입 받을 수 있음", "지원대상": "○ 국민연금 가입자 또는 가입자였던 사람 중 18세이상 60세미만의 구직급여 수급자, 다만 재산세 과세표준의 합이 6억원 또는 종합소득(사업 및 근로소득 제외)금액의 합이 1,680만원을 초과하는 분은 제외함", "소관기관명": "보건복지부", "서비스분야": "고용·창업", "신청기한": "구직급여종료일이 속하는 달의 다음달 15일 이내 신청 가능", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/B55201500004", "지원유형": "기타"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('149200000009', '생활안정자금(융자)', JSON '{"서비스ID": "149200000009", "서비스명": "생활안정자금(융자)", "서비스목적요약": "저소득 노동자 등에게 생활안정자금 융자 지원 ", "지원내용": "○ 저소득 노동자 등에 대한 생활안정자금(의료비, 혼례비, 장례비, 노부모부양비, 자녀양육비, 소액생계비)을 장기 저리로 융자(연 1.5%, 1년 거치 3년 또는 4년 원금균등분할상환", "지원대상": "○ 의료비·혼례비·장례비·노부모부양비·자녀양육비 : \r\n\r\n① 3개월 이상 근속 중(일용직은 신청일 이전 90일 이내에 고용보험법 시행규칙 별지 제7호서식의 고용보험 근로내용 확인신고서에 따른 근로일수가 45일 이상인 경우)\r\n\r\n② 월평균 소득이 3인 가구 기준 중위소득 2분의 1 이하인 노동자\r\n\r\n ※ 일용직은 소득 요건 적용하지 않음\r\n\r\n○ 소액생계비 : \r\n\r\n① 3개월 이상 근속 중(일용직은 신청일 이전 180일 이내 고용보험법 시행규칙 별지 제7호서식의 고용보험 근로내용 확인신고서에 따른 근로일수가 45일 이상인 경우...", "소관기관명": "고용노동부", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/149200000009", "지원유형": "현금(융자)"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('149200000092', '구직자 취업지원 서비스 제공', JSON '{"서비스ID": "149200000092", "서비스명": "구직자 취업지원 서비스 제공", "서비스목적요약": "구직자에게 일자리정보 및 직업지도 서비스 제공", "지원내용": "○ 구인 또는 구직의 신청을 받아 상담을 실시하고, 그 결과에 따라 필요한 취업·채용지원 서비스 제공\r\n\r\n - (1:1 일자리매칭) 구인 또는 구직 요건을 충족하는 구직자 또는 일자리를 탐색하여 근로계약이 성립하도록 알선\r\n - (구인·구직 만남의 날) 고용센터에서 구인기업과 구직자 간 현장면접의 기회를 제공하는 소규모 채용행사\r\n    ※ 48개 고용센터를 중심으로 월 2회 이상 \"일자리 수요데이\"를 개회하여 현장 채용면접과 구직자 취업역량 강화를 위한 프로그램 집중 지원\r\n - (동행면접) 고용세터 채용면접을 어려워하는 구직자...", "지원대상": "구직자 등 취업희망자", "소관기관명": "고용노동부", "서비스분야": "고용·창업", "신청기한": "채용행사와 프로그램의 종류 및 일정 등은 고용센터마다 상이하므로 고용24에서 일정 및 신청시기 등 직접 확인", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/149200000092", "지원유형": "상담/법률지원||서비스(일자리)"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('135200005004', '긴급복지 연료비 및 전기요금 지원', JSON '{"서비스ID": "135200005004", "서비스명": "긴급복지 연료비 및 전기요금 지원", "서비스목적요약": "긴급지원 주지원 가구 중 연료비, 전기요금이 필요한 경우 지원", "지원내용": "○ 전기요금 : 체납된 전기요금 중 50만원 범위 내에서 지원(1회)\r\n\r\n○ 연료비 : 난방을 위해 기름, 가스, 전기, 연탄, 화목 등의 구입 또는 사용에 필요한 비용 지원(가구당 월 150,000원, 동절기 10~3월에 한함)", "지원대상": "○ 긴급복지 주지원(생계, 주거지원) 을 받는 가구 중 연료비, 전기요금이 필요하다고 인정되는 가구\r\n   * 전기요금 : 주택용 전기가 단전(전류 제한기 부설 포함)된 가구", "소관기관명": "보건복지부", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/135200005004", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('135200005001', '긴급복지 주거지원', JSON '{"서비스ID": "135200005001", "서비스명": "긴급복지 주거지원", "서비스목적요약": "위기상황 발생으로 생계가 곤란한 가구에 임시거소 또는 주거비용 지원", "지원내용": "○ 지원대상 : 위기사유의 발생으로 임시거소(臨時居所) 제공 또는 주거비 지원이 필요하다고 인정되는 사람\r\n\r\n○ 원칙：시장·군수·구청장은 국가 또는 지방자치단체가 소유한 임시거소를 제공하거나 임시로 거처할 수 있는 주거를 확보하여 제공\r\n * 국가 또는 지방자치단체의 소유가 아닌 타인 소유의 임시거소를 제공한 경우, ① 임시거소 제공자가 거소사용 비용을 제2호 서식에 따라 청구 → ② 시장·군수·구청장이 임시거소 제공자에 지급\r\n\r\n○ 지원기준 : 지역별, 가구원수별 지원기준(대도시 4인가구의 경우, 662,500원)을 고려하여 ...", "지원대상": "○ 긴급복지지원법 제2조 각 호의 어느 하나에 해당하는 사유로 생계유지가 곤란한 사람\r\n\r\n<위기사유>\r\n1. 주소득자(主所得者)가 사망, 가출, 행방불명, 구금시설에 수용되는 등의 사유로 소득을 상실한 경우\r\n2. 중한 질병 또는 부상을 당한 경우\r\n3. 가구구성원으로부터 방임(放任) 또는 유기(遺棄)되거나 학대 등을 당한 경우\r\n4. 가정폭력 또는 가구구성원으로부터 성폭력을 당한 경우\r\n5. 화재 또는 자연재해 등으로 인하여 거주하는 주택 또는 건물에서 생활하기 곤란한 경우\r\n6. 주소득자 또는 부소득자의 휴업, 폐업 또는 사업...", "소관기관명": "보건복지부", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/135200005001", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('149200005002', '광역구직활동비', JSON '{"서비스ID": "149200005002", "서비스명": "광역구직활동비", "서비스목적요약": "구직급여 수급자 중 거주지에서 25km 이상 떨어진 곳에서 구직활동 시 지원", "지원내용": "○ 구직활동을 한 날에 소요된 교통비와 숙박료 지급", "지원대상": "○ 직업안정기관의 소개에 따라 거주지에서 25km 떨어진 곳에서 구직활동을 한 사람", "소관기관명": "고용노동부", "서비스분야": "고용·창업", "신청기한": "광역구직활동을 종료한 날부터 14일 이내 가능", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/149200005002", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('149200000063', '조기재취업수당', JSON '{"서비스ID": "149200000063", "서비스명": "조기재취업수당", "서비스목적요약": "구직급여 수급자 중 조기에 재취업한 경우 인센티브 지원(미지급일수의 1/2 일시지급)", "지원내용": "○ 잔여 소정급여일수의 1/2를 지급", "지원대상": "○ 수급자격자가 실업의 신고일로부터 14일이 지난 후 재취업한 날의 전날을 기준으로 구직급여 소정급여일수를 1/2 이상 남기고 재취업하여 12개월 이상 계속 고용되거나 사업을 영위한 경우(이직일 기준 65세 이상 수급자의 경우 6개월 이상 계속 고용되거나 사업을 영위할 것으로 고용노동부 장관이 인정하는 경우) 수당을 지급하며, 아래의 경우 중 어느 하나에 해당하면 지급하지 않음\r\n - 수급자가 마지막으로 이직한 사업장에 다시 취업한 경우\r\n - 수급자가 마지막으로 이직한 사업주와 합병, 분할 관계에 있거나 그 사업을 넘겨받은 사업주...", "소관기관명": "고용노동부", "서비스분야": "고용·창업", "신청기한": "조기 재취업하여 12개월 이상 고용(또는 사업 개시)된 날 다음 날부터 3년 이내 신청 가능", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/149200000063", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('135200005005', '긴급복지 의료지원', JSON '{"서비스ID": "135200005005", "서비스명": "긴급복지 의료지원", "서비스목적요약": "중한 질병 또는 부상으로 의료비를 감당하기 곤란한 사람에게 일시적으로 의료지원", "지원내용": "○ 300만원의 범위 내에서 의료기관 등이 긴급지원대상자에게 제공한 의료서비스 비용 중 약제비, 본인부담금 및 비급여 항목 \r\n    다만, 비급여 입원료와 비급여 식대 항목에 대하여는 지원하지 않음\r\n * 입원 또는 그에 준하는 정도의 질병 또는 부상에 따른 입원진료 및 당일 외래수술 지원(수술에 준하는 시술 포함, \r\n    당일 외래진료는 입원 및 수술진료와 연계되는 경우에 한하여 인정)\r\n *간병비, 의료기구 구입비, 제증명료, 보호자 식대, 비급여 도수치료비, 비급여입원료, 비급여식대는 의료지원 항목에 포함되지 않음 \r\n\r...", "지원대상": "○ 중한 질병 또는 부상으로 인하여 발생한 의료비를 감당하기 곤란한 사람 (지원 요청 후 사망한 자 포함)", "소관기관명": "보건복지부", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/135200005005", "지원유형": "서비스(의료)"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('149200000147', '구직자 취업역량강화 프로그램', JSON '{"서비스ID": "149200000147", "서비스명": "구직자 취업역량강화 프로그램", "서비스목적요약": "집단상담, 취업특강 등 구직자 취업역량강화프로그램 운영", "지원내용": "직업탐색, 구직기술 향상 등을 집중 지원하는 집단상담, 취업특강 등의 다양한 취업역량강화 프로그램 운영", "지원대상": "○ 직업선택을 고민하고 있거나 취업의욕 고취 및 구직기술 향상이 필요한 구직자", "소관기관명": "고용노동부", "서비스분야": "고용·창업", "신청기한": "접수기관 별 상이", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/149200000147", "지원유형": "기타(상담)||서비스(일자리)"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('WII000001320', '국가보훈대상자 취업지원', JSON '{"서비스ID": "WII000001320", "서비스명": "국가보훈대상자 취업지원", "서비스목적요약": "국가보훈대상자 중 취업지원대상자에게 보훈특별고용 및 특별채용 추천, 채용시험 가점", "지원내용": "○ 보훈특별고용 : 20명 이상(제조업체 200명 이상)을 고용하는 기업체 등 \r\n○ 일반직공무원등 특별채용 : 국가기관, 지방자치단체, 군부대 등 \r\n○ 채용시험의 가점 : 취업지원 실시기관 채용시험에 응시한 대상자 점수에 가점(5% 또는 10%)", "지원대상": "ㅇ 독립유공자 예우에 관한 법률 제16조\r\nㅇ 국가유공자 등 예우 및 지원에 관한 법률 제29조\r\nㅇ 보훈보상대상자 지원에 관한 법률 제33조\r\nㅇ 고엽제후유의증 등 환자지원에 관한 법률 제7조의9\r\nㅇ 5·18민주유공자예우 및 단체설립에 관한 법률 제20조\r\nㅇ 특수임무유공자 예우 및 단체설립에 관한 법률 제19조", "소관기관명": "국가보훈부", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/WII000001320", "지원유형": "서비스(일자리)||의료지원"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('B55271100008', '건설근로자 퇴직공제금 지급', JSON '{"서비스ID": "B55271100008", "서비스명": "건설근로자 퇴직공제금 지급", "서비스목적요약": "고용환경이 열악한 건설근로자에게 퇴직공제금을 지급", "지원내용": "○ 일용·임시직 건설노동자가 건설업 퇴직 시, 퇴직공제 가입사업장에서 납부한 공제부금에 이자를 더한 퇴직공제금 지급\r\n○ 장기적립한 노동자의 경우 특별퇴직공제금까지 추가 지급\r\n   ※ 적립일수 1,764일 이상 30만원 / 2,520일 이상 50만원 / 3,780일 이상 100만원", "지원대상": "1. 퇴직공제 적립일수 252일 이상인 건설근로자가 건설업에서 퇴직하거나 만 60세에 이른 경우\r\n2. 퇴직공제 적립일수 252일 미만인 건설근로자가 만 65세에 이른 경우\r\n3. 건설근로자가 사망한 경우", "소관기관명": "건설근로자공제회", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/B55271100008", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('149200000037', '직업훈련 생계비대부사업', JSON '{"서비스ID": "149200000037", "서비스명": "직업훈련 생계비대부사업", "서비스목적요약": "취약계층을 대상으로 장기 직업훈련 참여자에게 생계비 대부(융자 1인당 1,000만원 한도)", "지원내용": "○ 소득요건 : 가구원합산 연소득이 기준 중위소득의 80% 이하인 자\r\n  * KDT, 중장년내일센터 참여자는 100% 이하, 국기훈련 참여자는 120% 이하 \r\n\r\n○ 1인당 대부 한도액 : 1,000만 원 (특별고용지원업종 및 고용위기지역, 특별재난지역은 2,000만원)\r\n\r\n○ 월별 대부 한도액 : 200만 원(최소 50만 원) \r\n\r\n○ 상환 조건 : 연 1.0% 금리(1년 거치 3년 분할 상환, 2년 거치 4년 분할 상환, 3년 거치 5년 분할 상환 중 선택)\r\n\r\n○ 지원절차 : 근로복지공단에 직업훈련 생계비 대부를 신청...", "지원대상": "○  140시간 이상 직업훈련*에 참여하는 비정규직 근로자, 전직실업자, 무급휴직자, 자영업자인 피보험자 중 \r\n     가구원 합산 소득이 기준 중위소득의 80% 이하인 자\r\n     - 첨단산업 디지털 핵심 실무인재 양성훈련, 중장년내일센터 프로그램 참여자의 경우 기준 중위소득의 100%이하인 자, 국가기간산업직종 훈련 참여자의 경우 기준 중위소득의 120%이하인 자\r\n     - 전직실업자인 경우 실업급여 수급중인 자는 제외\r\n       * 직업훈련: 「국민 평생 직업능력 개발법」에 의해 지원되는 국민내일배움카드 과정(원격훈...", "소관기관명": "고용노동부", "서비스분야": "고용·창업", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/149200000037", "지원유형": "현금(융자)"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('999000000013', '고교 취업연계 장려금', JSON '{"서비스ID": "999000000013", "서비스명": "고교 취업연계 장려금", "서비스목적요약": "중소ㆍ중견기업 취업을 희망하는 직업계고 등 3학생에게 1인당 총 500만원  지원", "지원내용": "○ 학생 1인당 총 500만원 지원(3개월 재직 시 2백만원, 추가 9개월 재직 시 3백만원 후지급)", "지원대상": "○ 직업계고 및 일반고 직업교육위탁과정(6개월) 3학년 중 중소/중견기업에 취업한 자", "소관기관명": "교육부", "서비스분야": "고용·창업", "신청기한": "2024년 5~6월, 9~12월", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/999000000013", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('SD0000003857', '고용촉진장려금', JSON '{"서비스ID": "SD0000003857", "서비스명": "고용촉진장려금", "서비스목적요약": "대상 근로자 고용시 연 최대 720만원 지원", "지원내용": "○ 고용촉진장려금\r\n - 지원수준: 대상근로자 고용시 1년간 우선지원대상기업, 중견기업은 연 최대 720만원, 대규모기업은 연  360만원(6개월단위 지급, 사업주가 고용산재보험료징수법 제16조의10에 따라 신고한 보수 한도에서 지원)\r\n - 중증장애인, 여성가장 등은 최대 2년간 지원", "지원대상": "○ 직업안정기관 등에 구직 등록을 한 사람으로서 고용노동부 장관이 고시하는 취업지원프로그램 이수자를 고용하거나, 고용일 이전 1년 이내에 구직등록 이력과 1개월 이상 실업상태에 있는 중증장애인, 여성가장을 기간의 정함이 없는 근로자로 채용한 사업주", "소관기관명": "고용노동부", "서비스분야": "고용·창업", "신청기한": "지급대상 근로자를 고용한 날부터 12개월 이내에 첫번재 주기 고용촉진장려금을 신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/SD0000003857", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('B55190400005', '실업급여(구직급여) 수급자격 온라인 교육 서비스', JSON '{"서비스ID": "B55190400005", "서비스명": "실업급여(구직급여) 수급자격 온라인 교육 서비스", "서비스목적요약": "실업급여(구직급여)에 대한 전반적인 신청 및 제도 안내", "지원내용": "○ 수급자격 신청자 온라인 교육 서비스 (실업급여 신청 시 필수 교육)\r\n - 실업급여(구직급여)에 대한 전반적인 신청 및 제도 안내\r\n  ㆍ실업급여 정의\r\n  ㆍ구직급여 수급요건 및 관련 용어 안내\r\n  ㆍ수급자격 인정 신청 및 구직신청 절차 안내\r\n  ㆍ실업인정 및 조기재취업수당 안내\r\n  ㆍ실업급여 부정수급 안내", "지원대상": "○ 고용보험 가입자가 실직하여 아래 실업급여 수급 요건을 충족하는 자\r\n - 이직일 이전 18개월간(예술인·노무제공자: 24개월) 피보험단위기간이 통산하여 180일(예술인: 9개월, 노무제공자: 12개월) 이상일 것\r\n - 근로의 의사와 능력이 있음에도 불구하고 취업(영리를 목적으로 사업을 영위하는 경우 포함)하지 못한 상태에 있을 것\r\n - 재취업을 위한 노력을 적극적으로 할 것\r\n - 이직사유가 비자발적인 사유일 것(이직 사유가 법 제 58조에 따른 수급자격의 제한사유에 해당하지 아니할 것)", "소관기관명": "한국고용정보원", "서비스분야": "고용·창업", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/B55190400005", "지원유형": "기타(교육)"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('999000000040', '긴급복지 장제비 지원', JSON '{"서비스ID": "999000000040", "서비스명": "긴급복지 장제비 지원", "서비스목적요약": "긴급복지 주지원(생계,의료,주거,복지시설이용)가구구성원이 사망한 경우 장례소요비용 지원", "지원내용": "○ 긴급복지 주지원(생계,의료,주거,복지시설이용)을 받는 가구구성원이 사망한 경우 장례소요비용 지원\r\n  - 사체의 검안, 운반, 화장 또는 매장, 기타 장제조치를 행하는데 필요한 비용(1인당 80만원) 지원", "지원대상": "○ 긴급복지 주지원(생계,의료,주거,복지시설이용)대상  가구구성원이 사망한 경우", "소관기관명": "보건복지부", "서비스분야": "생활안정", "신청기한": "긴급복지 주지원(생계,의료,주거,사회복지시설이용) 대상 가구구성원이 사망한 경우", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/999000000040", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('641000000164', '경기도형긴급복지지원', JSON '{"서비스ID": "641000000164", "서비스명": "경기도형긴급복지지원", "서비스목적요약": "1년 이내 위기상황이 발생한 경기도 가구에 대한 단기·신속 안전장치", "지원내용": "○ 생계지원 : 식료품비, 의복비 등 1개월 생계유지비 1,995천 원(4인가구 기준) ※ 가구원수에 따라 지원금액 상이\r\n○ 의료지원\r\n   - 검사 및 치료 등 비급여 의료 서비스 : 300만 원 이내\r\n   - 간병비 : 300만 원이내\r\n   - 항암치료비 : 100만 원 이내\r\n○ 주거지원\r\n   - 임시거소 제공 또는 이에 해당하는 비용 : 663천 원(3~4인) ※ 가구원수에 따라 지원금액 상이\r\n   - 주거지 마련을 위한 임대보증금 일부 비용 : 보증금 500만 원 이내\r\n○ 긴급통합지원 - 현장확인결과 필요한 지원...", "지원대상": "○ 위기상황이 발생한 1년 이내의 가정으로 소득, 재산, 금융재산 기준을 충족하는 경우\r\n○ 소득기준 : 기준 중위소득100% 이하(4인가구 기준 650만 원) ※ 가구원 수에 따라 기준금액 상이\r\n○ 재산기준 : 특례시지역 372백만 원, 시지역 310백만 원 이하, 군지역 194백만 원 이하\r\n○ 금융재산 기준 : 1,850만원 이하(4인가구 기준, 생활준비금 포함) ※ 가구원 수에 따라 생활준비금 금액 상이", "소관기관명": "경기도", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/641000000164", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('149200000008', '무급 고용유지조치 근로자지원', JSON '{"서비스ID": "149200000008", "서비스명": "무급 고용유지조치 근로자지원", "서비스목적요약": "무급 고용유지조치 계획을 승인받은 경우 평균임금의 50% 범위 내에서 근로자 지원", "지원내용": "○ 무급 고용유지조치 대상 피보험자 지원\r\n - 평균임금의 50% 범위 내에서 직업안정기관의 장이 결정(1일 68,100원,  재직기간 중 180일 한도)\r\n - 사업주에 대해서는 직업 능력개발향상비용 1인당 10만원 범위 내에서 지원", "지원대상": "○  고용조정이 불가피한 상황임에도 무급 고용유지조치 계획을 승인받고 근로자를 계속고용하는 사업주 및 고용유지조치 대상 근로자", "소관기관명": "고용노동부", "서비스분야": "고용·창업", "신청기한": "고용유지조치 실시 30일 전까지 무급 고용유지조치 계획서 제출", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/149200000008", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('149200005008', '자영업자 실업급여', JSON '{"서비스ID": "149200005008", "서비스명": "자영업자 실업급여", "서비스목적요약": "비자발적으로 폐업한 자영업자에 대한 실업급여 지급", "지원내용": "○ 고용보험 가입(고용산재보험료징수법 제49조의2)\r\n  -  근로자를 사용하지 아니하거나 50명 미만의 근로자를 사용하는 사업주* 중 가입희망자(임의가입)\r\n   *  ①사업자등록을 하고 사업을 영위하는 사람, ②고유번호를 부여받은 자영업자로서 가정어린이집, 민간어린이집, 노인장기요양기관을 운영하는 사람, ③농어업경영정보를 등록하고 농어업을 영위하는 사람\r\n  -  고용보험료는 기준보수액의 2.25%\r\n\r\n○ 실업급여 지급(고용보험법 제4장(실업급여) 제4절(자영업자인 피보험자에 대한 실업급여 적용의 특례) 제69조의2부터 제69...", "지원대상": "○ 구직급여 수급요건(고용보험법 제69조의3) 폐업한 자영업자인 피보험자가 아래 요건을 모두 갖춘 경우 지급 \r\n -  폐업일 이전 24개월간 제41조제1항 단서에 따라 자영업자인 피보험자로서 갖춘 피보험 단위기간이 합산하여 1년 이상일 것\r\n -  근로의 의사와 능력에도 불구하고 취업하지 못한 상태에 있을 것\r\n -  폐업사유가 고용보험법 제69조의7에 따른 수급자격의 제한 사유에 해당하지 아니할 것\r\n -  재취업을 위한 노력을 적극적으로 할 것", "소관기관명": "고용노동부", "서비스분야": "고용·창업", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/149200005008", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('SD0000016137', '긴급복지 교육지원', JSON '{"서비스ID": "SD0000016137", "서비스명": "긴급복지 교육지원", "서비스목적요약": "긴급복지 주지원 가구 중 학비 지원이 필요한 자녀에 대해 현금 지원", "지원내용": "○ 지원기준\r\n  - 초등학생 : 127,900원\r\n  - 중학생 : 180,000원\r\n  - 고등학생 : 214,000원 및 수업료와 입학금(해당 학교장이 고지한 금액) \r\n  * 고등학생이 수업료 및 입학금을 지원받은 경우도 전액 지원", "지원대상": "○ 긴급복지 주지원(생계, 주거, 복지시설이용 지원)을 받는 가구 중 초중고 입학생 또는 재학생\r\n  * 지원제외대상 : 긴급지원대상자로서 국가 또는 지방자치단체 등으로부터 타 교육지원을 받고 있는 사람(국가보훈대상자 지원(수업료 면제), 교육급여(맞춤형 급여) 등)", "소관기관명": "보건복지부", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/SD0000016137", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('999000000009', '고령자 계속고용장려금', JSON '{"서비스ID": "999000000009", "서비스명": "고령자 계속고용장려금", "서비스목적요약": "우선지원대상기업 등에게 정년도래자 1인당 분기 90만원씩 3년간 장려금 지원", "지원내용": "○ 정년도래자를 계속고용하는 사업주에게 계속고용 근로자 1인당 분기 90만원씩 3년간 지원(비수도권 사업주의 경우, ''26.1분기 지원대상부터 근로자 1인당 분기 120만원씩 3년간 지원)", "지원대상": "○ 우선지원대상기업, 중견기업 및 사회적기업\r\n\r\n* 60세이상 피보험자 수가 30%초과 기업 제외", "소관기관명": "고용노동부", "서비스분야": "고용·창업", "신청기한": "분기별", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/999000000009", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('149200005012', '고령자고용지원금', JSON '{"서비스ID": "149200005012", "서비스명": "고령자고용지원금", "서비스목적요약": "1년이상 근로한 60세이상 근로3년평균 대비하여 증가한 경우\r\n증가 1인당 분기 30만원을 ", "지원내용": "1년이상 근로한 60세이상 근로3년평균 대비하여 증가한 경우\r\n증가 1인당 분기 30만원을 2년간 지원", "지원대상": "ㅇ 우선지원대상기업, 중견기업 및 사회적기업", "소관기관명": "고용노동부", "서비스분야": "생활안정", "신청기한": "분기별 신청( 매분기말 다음달)", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/149200005012", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('611000000149', '서울형긴급복지지원', JSON '{"서비스ID": "611000000149", "서비스명": "서울형긴급복지지원", "서비스목적요약": "위기상황에 처한 취약계층 시민에게 생계, 의료, 주거비 등 신속 지원", "지원내용": "○ 긴급한 위기상황으로 어려움으로 겪는 취약계층 시민에게 생계비, 의료비, 주거비 등을 신속하게 지원", "지원대상": "○ 위기상황에 처한 중위소득 100%이하 서울시민 재산 409백만원 이하, 금융재산 10백만원 이하", "소관기관명": "서울특별시", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/611000000149", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('B55117700003', '항공산업분야 취업지원 프로그램', JSON '{"서비스ID": "B55117700003", "서비스명": "항공산업분야 취업지원 프로그램", "서비스목적요약": "항공산업분야의 다양한 취업지원 프로그램 운영", "지원내용": "○ 항공산업분야 다양한 취업지원 프로그램 운영 통한 활성화 \r\n - 항공산업 취업박람회, 취업 컨설팅(7개), 일지라 지원사업(4개) 등 다양한 프로그램 운영", "지원대상": "항공산업 분야 구직자, 취업준비생(청년 및 중장년층 등)", "소관기관명": "인천국제공항공사", "서비스분야": "고용·창업", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/B55117700003", "지원유형": "서비스(일자리)"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('149200000018', '산재근로자 생활안정자금 융자', JSON '{"서비스ID": "149200000018", "서비스명": "산재근로자 생활안정자금 융자", "서비스목적요약": "일정기준의 중위소득 이하인 자를 대상으로 세대 당 2천만원 범위에서 융자 지원", "지원내용": "○ 융자이율 : 연리 1.25%(신용보증료 연 1.0% 별도 부담), 융자기간 : 5년 이내\r\n○ 상환방법 : 1년거치 4년 원금 균등분활 상환,  2년거치 3년 원금 균등분할 상환,  3년거치 2년 원금 균등분할 상환 중에서 택1(거치기간 변경 불가) \r\n○ 융자한도 : 세대 당 2,000만원 이내 범위에서 각 융자종류별 한도내 융자\r\n - 주택 이전비, 차량 구입비는 1,500만원 한도\r\n - 의료비, 혼례비, 장례비, 취업안정자금,자녀양육비는 각 1,000만원 한도", "지원대상": "○ 월평균소득이 보건복지부 장관이 고시하는 3인 가구 기준 중위소득 이하인 자로 다음에 해당하는 자\r\n - 산재사망근로자의 유족 중 수급권 1순위자(방계 일시금 수급권자 제외) \r\n - 상병보상연금 수급자, 산재장해등급 1~9급 판정자 \r\n - 융자신청일 현재 3개월 이상 요양 중인 산재노동자로서 평균임금이 최저임금 이하인 자(의료비, 혼례비, 장례비에 한함)\r\n - 융자신청일 현재 5년 이상 장기 요양 중인 이황화탄소 질병판정자", "소관기관명": "고용노동부", "서비스분야": "생활안정", "신청기한": "(의료비) 진료일 또는 의료비 납부일부터 1년이내 (혼례비) 결혼일 전·후 또는 혼인신고일부터 90일 이내 (장례비) 사망일부터 90일 이내 (취업안정자금) 직장복귀일부터 1년이내 (차량구입비) 소유권 등록일 또는 차량(건설기계)매매계약이루터 90일 이내 또는 차량인수일 이전 30일 이내 (주택이전비) 임대차계약일 또는 전입일부터 90일 이내 (자녀양육비) 자년가 13세에 도달하는 시기 이내", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/149200000018", "지원유형": "현금(융자)"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('B55307700011', '청년고용연계자금', JSON '{"서비스ID": "B55307700011", "서비스명": "청년고용연계자금", "서비스목적요약": "청년 소상공인의 경영활성화 및 청년 일자리를 창출한 소상공인 지원", "지원내용": "□ 융자범위\r\n◦ 운전자금 : 제품생산 비용 및 기업경영에 필요한 자금\r\n\r\n□ 융자조건\r\n◦ 대출금리(변동금리) : 정책자금 기준금리\r\n◦ 대출기간 : 5년 이내(거치기간 2년 포함)\r\n◦ 대출한도 : 7천만원(청년고용연계자금 대출잔액 합산)\r\n◦ 융자방식 : 금융기관을 통한 대리대출", "지원대상": "다음 각 호 중 1개 이상의 요건을 충족하는 소상공인\r\n① 업력 3년 미만의 청년 소상공인(만39세 이하)\r\n② 상시근로자 중 과반수 이상이 청년 근로자(만39세 이하)인 소상공인\r\n③ 최근 1년 이내 청년 근로자 1인 이상 고용하고 유지 중인 소상공인", "소관기관명": "소상공인시장진흥공단", "서비스분야": "고용·창업", "신청기한": "소상공인정책자금 사이트 별도 안내", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/B55307700011", "지원유형": "현금(융자)"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('569000000365', '저소득 한부모가족 생활안정지원금 지원', JSON '{"서비스ID": "569000000365", "서비스명": "저소득 한부모가족 생활안정지원금 지원", "서비스목적요약": "저소득 한부모가족에게 생활안정지원금(교통비, 학습지원비, 명절지원금, 월동비) 지원", "지원내용": "○ 교통비 \r\n - 대상 : 중·고등학교 재학중인 자녀(교육급여 대상자 제외)\r\n - 금액 : 개인별 연 10만원\r\n - 지원시기 : 연 2회 지원(1회 5만원)\r\n\r\n○ 학습지원비\r\n - 대상 : 초·중·고등학교 재학중인 자녀(교육급여 대상자 제외)\r\n - 금액 : 초등학생 20만원, 중학생 25만원, 고등학생 35만원\r\n - 지원시기 : 연 2회 지원(상반기 초10, 중15, 고20만원 / 하반기 초10, 중10, 고15만원)\r\n\r\n○ 명절지원금\r\n - 대상 : 저소득 한부모가족 세대 중 기준 중위소득 63%이하(청소년한부모는 ...", "지원대상": "○ (한부모가족 자녀 양육비 등 지원) 기준 중위소득 63% 이하인 가족의 18세 미만 자녀\r\n  - 단, 고등학교 재학(고3, 12월까지) 중인 경우 22세 미만 자녀\r\n\r\n○ (청소년한부모 아동양육 및 자립지원) 기준 중위소득 65% 이하인 청소년한부모의 자녀", "소관기관명": "세종특별자치시", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/569000000365", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('999000000010', '장애인 취업성공패키지', JSON '{"서비스ID": "999000000010", "서비스명": "장애인 취업성공패키지", "서비스목적요약": "장애인에게 단계별 취업지원프로그램 제공(상담 및 취업계획 → 직업훈련 → 취업알선)", "지원내용": "○ [1단계] : 상담 및 취업활동계획\r\n\r\n○ [2단계] : 취업역량 강화\r\n\r\n   - 저소득층 구직촉진수당 월 50만원,최대 6개월(2유형 참여자에 한함)\r\n\r\n○ [3단계] : 고용 유지\r\n\r\n   - 취업성공 후 3개월 근속유지 (취업성공수당 30만원 지급)\r\n\r\n   - 취업성공 후 6개월 근속유지 (취업성공수당 40만원 지급)\r\n\r\n   - 취업성공 후 12개월 근속유지 (취업성공수당 80만원 지급)", "지원대상": "○  만 18세 이상 69세 이하 구직장애인(중위소득 60% 이하 저소득층 포함)", "소관기관명": "고용노동부", "서비스분야": "고용·창업", "신청기한": "한국장애인고용공단 서비스담당자 확인필요", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/999000000010", "지원유형": "서비스(일자리)"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('642000000700', '저소득 한부모가정 생활안정 지원', JSON '{"서비스ID": "642000000700", "서비스명": "저소득 한부모가정 생활안정 지원", "서비스목적요약": "저소득 한부모가족 생활안정 지원", "지원내용": "○ 한부모가족 자녀 대학신입생 생활자립금(1인 1회 170만 원)\r\n○ 난방연료비(가구당 연 35만 원)", "지원대상": "○ 강원특별자치도에 주민등록주소를 두고있는 기준중위소득 65%이하 한부모가족", "소관기관명": "강원특별자치도", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/642000000700", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('SD0000003418', '고용유지지원금 지원', JSON '{"서비스ID": "SD0000003418", "서비스명": "고용유지지원금 지원", "서비스목적요약": "고용조정이 불가피한 사업주가 휴업 및 휴직을 통해 근로자 계속 고용시 인건비 일부 지원", "지원내용": "○ 고용유지지원금\r\n  - 역(曆)에 따른 1개월의 소정근로시간 중 100분의 20 이상을 단축하고 그 단축된 근로시간에 대한 임금을 보전하기 위하여 금품을 지급한 사업주\r\n  - 사업주가 지급한 금품의 2/3(대규모 기업 1/2～2/3) 지원(1일 68,100원, 연간 180일 한도)", "지원대상": "○ 고용조정이 불가피한 상황임에도 휴업,휴직 등 고용유지조치를 통해 수당을 지급하고 근로자를 계속 고용하는 사업주", "소관기관명": "고용노동부", "서비스분야": "고용·창업", "신청기한": "고용유지조치 실시 전날까지 고용유지조치계획서 제출", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/SD0000003418", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('149200000093', '고용안정장려금지원(정규직전환지원)', JSON '{"서비스ID": "149200000093", "서비스명": "고용안정장려금지원(정규직전환지원)", "서비스목적요약": "비정규직 근로자 정규직 전환 시 임금상승분와 간접노무비 지원", "지원내용": "○ 정규직전환에 따른 임금상승분와 간접노무비를 최대 1년간 지원(정규직 전환 시 임금증가액에 따라 차등 지원)\r\n   - (임금증가액이 월 20만원 이상) 월 60만원\r\n   - (임금증가액이 월 20만원 미만) 월 40만원", "지원대상": "○ 비정규직 근로자(기간제, 파견, 사내 하도급 근로자) 및 노무제공자를 정규직으로 전환하는 30인 미만 사업주\r\n - 다만, (1) 국가, 지방자치단체 등 \"부패방지 및 국민권익위원회의 설치와 운영에 관한 법률\" 제2조제1호 가목에서 다목까지의 규정에 따른 기관, (2) \"공공기관의 운영에 관한 법률\" 제4조에 따른 공공기관, \"지방공기업법\" 제2조에 따른 지방공기업, (3) 일반유흥, 무도유흥, 기타주점업, 갬블링 및 베팅업 등 \"중소기업인력지원 특별법 시행령\" 제2조에서 정한 업종, (4) \"근로기준법\" 제43조의2에 따라 임...", "소관기관명": "고용노동부", "서비스분야": "고용·창업", "신청기한": "연중수시", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/149200000093", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('B49000700017', '해외취업정착지원금', JSON '{"서비스ID": "B49000700017", "서비스명": "해외취업정착지원금", "서비스목적요약": "해외취업에 성공 시 해외에서의 초기 정착 및 장기 근속을 유인하기 위한 비용 지원\r\n", "지원내용": "○ 지원규모: 3,900명\r\n\r\n○ 지원금액: 1인당 최대 500만원  \r\n - 취업 후 1개월 후 250만원(1차), 6개월 후 100만원(2차), 12개월 후 150만원(3차)", "지원대상": "○ 만 34세 이하 청년으로 해외취업한 자\r\n  - 취업일 기준 본인 및 부모(미혼), 본인 및 배우자, 자녀(기혼)의 합산 소득이 일정수준 이하 \r\n  - 월드잡플러스 내 사전구직등록자\r\n  - 취업비자, 연봉 1,700만원 이상으로 근로계약서를 작성한 자(단순노무직종 제외) \r\n\r\n○ 자세한 사항은 월드잡플러스 공고내용 참조", "소관기관명": "고용노동부", "서비스분야": "고용·창업", "신청기한": "접수기관 별 상이", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/B49000700017", "지원유형": "서비스(일자리)"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('SD0000003276', '고용창출장려금(일자리 함께하기, 국내복귀기업 지원, 신중년 적합직무 지원)', JSON '{"서비스ID": "SD0000003276", "서비스명": "고용창출장려금(일자리 함께하기, 국내복귀기업 지원, 신중년 적합직무 지원)", "서비스목적요약": "일자리 함께하기 지원, 국내복귀기업 지원, 신중년 적합직무 등 지원", "지원내용": "○ (일자리함께하기 지원) 일자리함께하기 제도를 도입․확대하여 근로자수가 증가한 경우 증가근로자 수 1인당 연간 최대 480~960만원, 임금감소액 일부 또는 전부를 사업주가 보전한 경우 사업주 지급 금액의 80% 한도로 연간 최대 120~480만원 지원\r\n○ (국내복귀기업 고용지원) 국내복귀기업으로 지정 후 5년 이내인 기업의 근로자수가 증가한 경우 증가근로자 수 1인당 우선지원대상기업 연간 최대 720만원, 중견기업 연간 최대 360만원 지원 \r\n○ (신중년 적합직무 고용지원) 만 50세 이상 실업자를 신중년 적합직무에 6개월 ...", "지원대상": "○ 일자리 창출 사업주(소상공인, 중소기업, 중견기업, 대기업 등)\r\n\r\n○ 지원제외대상 사업주 \r\n - 국가, 지자체, 공공기관\r\n - 일반유흥․무도유흥․기타주점업, 갬블링 및 베팅업 등 중소기업인력지원 특별법 시행령 제2조에서 정한 업종 \r\n - 근로기준법 제43조2에 따라 임금 등을 체불하여 명단이 공개중인 사업주\r\n - 산업안전보건법 제10조에 따라 중대산업재해 발생 등으로 명단이 공표 중인 사업주\r\n - 고용창출장려금 지급대상자를 고용한 사업주가 해당 근로자의 이직(해당 사업주가 해당 근로자를 고용하기 전 1년 이내에 이직...", "소관기관명": "고용노동부", "서비스분야": "고용·창업", "신청기한": "지원대상 근로자를 고용한 날부터 12개월 이내에 첫번째 주기 장려금 신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/SD0000003276", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('149200000016', '산재근로자 직업훈련', JSON '{"서비스ID": "149200000016", "서비스명": "산재근로자 직업훈련", "서비스목적요약": "산재장해인의 재취업을 위해 직업훈련비용 및 수당을 지급", "지원내용": "○ 재취업을 위한 직업훈련 신청 시 훈련비용 및 훈련수당 지원 \r\n - (직업훈련비용) 1인당 12개월 이내 2회까지 지원, 국민평생직업능력개발법에 따른 직업능력개발훈련 및 한국장애인고용공단의 위탁훈련은 정부지원승인 훈련비, 그 이외 훈련은 1인당 6백만원 \r\n - (직업훈련수당) 1일당 최저임금액의 범위 내 훈련시간에 따라 차등 지급(1일 2시간 미만의 훈련은 부지급)", "지원대상": "○ 직업훈련 신청일 현재 산재 장해등급 제1급~12급 어느 하나에 해당한 자로, 취업(자영업 포함)하고 있지 않으며, 고용노동부 등 다른 직업훈련을 받고 있지 아니할 것", "소관기관명": "고용노동부", "서비스분야": "고용·창업", "신청기한": "○ (급여)장해판정일로부터 3년 이내(2021.2.1. 1년이내에서 3년이내로 확대)", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/149200000016", "지원유형": "서비스(일자리)"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('149200000040', '외국인 고용허가제', JSON '{"서비스ID": "149200000040", "서비스명": "외국인 고용허가제", "서비스목적요약": "중소사업장 등을 위해 외국인력 고용허가제, 상담 및 지원센터 등 운영", "지원내용": "○ 고용허가제\r\n - 내국인을 구하지 못한 중소기업이 정부로부터 고용허가서를 발급받아 합법적으로 비전문 외국인력을 고용할 수 있는 제도\r\n\r\n○ 외국인력상담센터\r\n - 외국인노동자와 고용사업주에 대한 고충 상담 등\r\n\r\n○ 외국인노동자 지원센터\r\n - 고충 상담, 한국어, 생활법률 교육 등", "지원대상": "○ 고용허가제 허용업종(제조업, 농축산업, 어업, 건설업, 서비스업, 임업, 광업)\r\n - 외국인력 고용 허용 업종, 고용 허용 인원은 고용노동부 홈페이지의 외국인력정책위원회 결정사항 공고 혹은 고용허가제 홈페이지(www.eps.go.kr)를 참고하시기 바랍니다.\r\n\r\n○ 외국인력상담센터(전화 1577-0071)\r\n - 외국인노동자와 사업주가 전화 상담을 통해 신속하게 고충을 해결할 수 있도록 외국인력상담센터 운영\r\n\r\n○ 외국인노동자 지원센터(전국 19개소)\r\n - 문화적 차이와 언어소통의 한계로 인해 여러 가지 어려움을 겪고 있...", "소관기관명": "고용노동부", "서비스분야": "고용·창업", "신청기한": "접수기관 별 상이", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/149200000040", "지원유형": "서비스(일자리)"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('B49000100215', '중소기업퇴직연금기금제도(푸른씨앗) 사업주 및 근로자 지원', JSON '{"서비스ID": "B49000100215", "서비스명": "중소기업퇴직연금기금제도(푸른씨앗) 사업주 및 근로자 지원", "서비스목적요약": " 수수료 면제 및 사업주 및 근로자에 지원금 지급", "지원내용": "O 수수료 0원(3년간 면제)\r\n   . ''26년 중소기업퇴직연금기금제도 신규 가입시\r\n\r\nO 사업주 및 근로자 지원금(3년)\r\n  . 전년도 고용보험 월평균보수액 281만원 미만 근로자 1인당 최대 28만 1천원(''26년 기준 최저임금 130% 수준)", "지원대상": "중소기업퇴직연금기금제도에 가입한 상시근로자수 30명 이하 사업주 및 근로자", "소관기관명": "근로복지공단", "서비스분야": "고용·창업", "신청기한": "수수료: 기금제도 가입 시 3년 면제/ 지원금: 해당 사업장이 기금제도 최초 가입한 날 부터 3년 이내", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/B49000100215", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('628000000123', 'SOS 긴급복지 지원', JSON '{"서비스ID": "628000000123", "서비스명": "SOS 긴급복지 지원", "서비스목적요약": "위기상황에 처한 가구에 생계비, 의료비, 주거비 긴급지원", "지원내용": "○ 10가지 위기사유 및 소득·재산 등 기준을 충족하는 가구에 생계비(4인, 1,994,600원), 의료비(300만원 이내), 주거비(4인, 662,500원 이내) 등 지원", "지원대상": "○ 아래 사항을 모두 충족하는 자 \r\n\r\n - 10가지 위기사유 : 소득상실, 중한 질병, 휴·폐업, 복지사각지대 발굴대상자 등  \r\n\r\n - 소득기준 : 기준 중위소득 100% 이하 \r\n\r\n - 재산기준 : 369백만원 이하\r\n\r\n - 금융재산 : 10백만원 이하", "소관기관명": "인천광역시", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/628000000123", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('149200000053', '장애인고용장려금지원', JSON '{"서비스ID": "149200000053", "서비스명": "장애인고용장려금지원", "서비스목적요약": "장애인고용 사업주에게 조건에 따라 1인당 월 35~90만원의 고용장려금 지급", "지원내용": "○ 의무 고용률 초과 고용 장애인 근로자의 장애 정도, 성별에 따라 1인당 월 35만 원~90만 원을 지급\r\n\r\n○ 고용장려금 지급 단가 기준\r\n - (경증남성) 35만 원\r\n - (경증여성) 50만 원\r\n - (중증남성) 70만 원\r\n - (중증여성) 90만 원", "지원대상": "○ 월별 상시근로자의 3.1%(공공기관 및 준정부기관 3.8%)를 초과하여 장애인을 고용한 사업주에게 월별 초과 고용한 장애인 근로자 수에 지급단가(35~90만원)를 곱한 금액을 고용장려금으로 지원\r\n - 단, 최저임금 이상자 또는 최저임금 적용 제외 인가를 받은 장애인에 한해 지원", "소관기관명": "고용노동부", "서비스분야": "고용·창업", "신청기한": "○ 1월 1일부터 3월 31일까지의 장애인근로자 고용에 해당하는 장려금 : 해당연도 4월 1일 이후 3년간○ 4월 1일부터 6월 30일까지의 장애인근로자 고용에 해당하는 장려금 : 해당연도 7월 1일 이후 3년간○ 7월 1일부터 9월 30일까지의 장애인근로자 고용에 해당하는 장려금 : 해당연도 10월 1일 이후 3년간○ 10월 1일부터 12월 31일까지의 장애인근로자 고용에 해당하는 장려금 : 다음연도 1월 1일 이후 3년간", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/149200000053", "지원유형": "서비스(일자리)"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('999000000020', '제대군인 취업지원', JSON '{"서비스ID": "999000000020", "서비스명": "제대군인 취업지원", "서비스목적요약": "장기복무 제대군인 대상에게 보훈특별고용 및 직업교육 훈련 제공", "지원내용": "○  20인 이상(제조업체 200인 이상)을 고용하는 기업체 등에 보훈특별고용\r\n\r\n○  국가 또는 지방자치단체, 군부대, 국․공립학교 특별채용", "지원대상": "○  10년 이상 장기복무 제대군인 본인", "소관기관명": "국가보훈부", "서비스분야": "생활안정", "신청기한": "수시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/999000000020", "지원유형": "서비스(일자리)"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('641000000157', '1인 소상공인 고용보험료 지원', JSON '{"서비스ID": "641000000157", "서비스명": "1인 소상공인 고용보험료 지원", "서비스목적요약": "1인 소상공인에게 월 납입 고용보험료 일부 지원", "지원내용": "○ 근로자가 없는 1인 소상공인이 가입 후 납입한 자영업자 고용보험료의 20~30%, 분기별 지원(최대 5년)", "지원대상": "○ 근로자를 고용하지 않은 1인 소상공인 중 자영업자 고용보험에 가입한 자", "소관기관명": "경기도", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/641000000157", "지원유형": "현금(보험)"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('628000000129', '구직청년 드림체크카드 지원', JSON '{"서비스ID": "628000000129", "서비스명": "구직청년 드림체크카드 지원", "서비스목적요약": "구직청년에게 취업활동비 지원", "지원내용": "○ 구직청년 1인당 최대 300만원 취업활동비 지원(월 50만원/최대6개월, 구직활동에 필요한 직접비, 간접비로 사용 가능)\r\n○ 인천e음 소비쿠폰 20만원 + 드림체크카드 30만원 병행지급 (드림체크카드 전액, 인천e음 소비쿠폰 전액 선택 가능)", "지원대상": "○ 만18세~39세 인천 거주 미취업 청년\r\n○ 소득기준 : 기준 중위소득 50%~150% 이하", "소관기관명": "인천광역시", "서비스분야": "고용·창업", "신청기한": "2026.  3. 3. ~ 3. 18.", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/628000000129", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('135200005002', '긴급복지 해산비 지원', JSON '{"서비스ID": "135200005002", "서비스명": "긴급복지 해산비 지원", "서비스목적요약": "긴급지원 주지원대상자(가구구성원 포함)가 출산(예정)한 경우 현금 지원(1인당 70만원) ", "지원내용": "○ 조산 및 분만 후의 필요한 조치와 보호를 위한 지원 : 1인당 700천원 현금 지급(쌍둥이 출산 시 1,400천원 지급)\r\n * 긴급지원 주지원(생계, 의료, 주거, 복지시설이용 지원)을 받는 가구 중 해산비 지원이 필요하다고 인정되는 가구", "지원대상": "○ 긴급복지 주지원(생계, 의료, 주거, 복지시설이용 지원)을 받는 대상자(가구구성원 포함)가 출산 또는 출산예정인 경우", "소관기관명": "보건복지부", "서비스분야": "생활안정", "신청기한": "긴급지원 대상자 출산시", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/135200005002", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('645000000148', '전북형 청년 취업 지원', JSON '{"서비스ID": "645000000148", "서비스명": "전북형 청년 취업 지원", "서비스목적요약": "기업이 청년 추가고용시 인건비 지원, \r\n청년에게 취업장려금 지원", "지원내용": "ㅇ (기업) 인건비 월 70만원, 1년(연 840만원)\r\nㅇ (청년) 2년간 근속 시 최대 300만원(100만원×3회)", "지원대상": "○ (기업) 도내 소재 고용보험가입 3인이상 기업이 상시근로자 외 청년을 추가 채용시 지원\r\n○ (청년) 전북형 청년취업지원사업에 취업한 청년(만18~39세)", "소관기관명": "전북특별자치도", "서비스분야": "고용·창업", "신청기한": "접수기관 별 상이", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/645000000148", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('611000000144', '취업날개 서비스', JSON '{"서비스ID": "611000000144", "서비스명": "취업날개 서비스", "서비스목적요약": "서울시 거주 청년에게 면접정장 무료대여 지원", "지원내용": "- 1회에 3박 4일간, 1인당 연 10회까지 대여 가능\r\n\r\n- 운영기관 : 12개 대여업체(15개소)\r\n마이스윗인터뷰(신촌홍대), 열린옷장(건대성수), 체인지레이디(왕십리, 강남), 슈트갤러리(회기), 야베스컬렉션(이수), 드림윙즈(신촌홍대),  달콤정장(성북, 태릉), 스완제이서북(노원, 신림), 종로신사(종로), 강동원정장(천호), 정장명가(송파), 가온핏정장(영등포)", "지원대상": "서울시 거주 청년(고교졸업예정자 ~ 39세 이하) \r\n※ 주민등록지가 서울인 청년 및 추가증빙을 통하여 서울에 거소를 두고 있음이 확인된 청년", "소관기관명": "서울특별시", "서비스분야": "고용·창업", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/611000000144", "지원유형": "현물"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('149200000030', '체불청산 지원 융자(사업주 및 근로자)', JSON '{"서비스ID": "149200000030", "서비스명": "체불청산 지원 융자(사업주 및 근로자)", "서비스목적요약": "근로자들에게 임금을 체불한 사업주와 임금체불로 생계에 어려움을 겪는 근로자에게 융자 지원", "지원내용": "<체불청산지원 사업주 융자>\r\n\r\n○ 경영상 어려움 등으로 체불이 발생한 사업주에게 융자를 실시하고 융자금은 근로자에게 직접 지급하여  체불임금등 청산을 지원\r\n - 사업장당 1억5000만원 한도, 근로자 1인당 1500만원 한도\r\n\r\n○ 이자율\r\n - 담보: 2.2%, 신용 및 연대보증: 3.7%\r\n\r\n○ 상환기간\r\n - 1년 또는 2년 거치 후 3년 또는 4년 분기별 균등 분할상환\r\n\r\n\r\n<체불근로자 생계비 융자>\r\n\r\n○ 임금체불로 생계에 어려움을 겪는 근로자에게 저금리로 생계비를 융자\r\n - 재직자 및 퇴직자 1인당 1,0...", "지원대상": "<체불청산지원 사업주 융자>\r\n\r\n○ 사업주 요건\r\n - 산재보험 적용 대상이 되는 가동사업장으로 6개월 이상 해당 사업을 경영하고 있으며, 경영상 어려움으로 체불이 발생한 사업주\r\n\r\n○ 근로자 요건\r\n - 퇴직근로자: 신청일까지 6개월 이상 계속 근로하고 신청일 기준 1년 이내에 퇴직한 근로자\r\n - 재직근로자: 신청일까지 6개월 이상 계속 근로하고 있는 근로자\r\n\r\n\r\n<체불근로자 생계비 융자>\r\n\r\n○ 근로자 요건\r\n - 퇴직근로자: 체불 사업장에서 융자 신청일 이전 6개월 이내에 퇴직\r\n - 재직근로자: 체불 사업장(폐업 ...", "소관기관명": "고용노동부", "서비스분야": "고용·창업", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/149200000030", "지원유형": "현금(융자)"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('538000000124', '저소득 주민 생활안정지원', JSON '{"서비스ID": "538000000124", "서비스명": "저소득 주민 생활안정지원", "서비스목적요약": "기초수급자 초등학생 학원비, 중고등학생 통학교통비, 초중고 수학여행비 및 한부모가족 지원", "지원내용": "○ 초등학생 학원비, 중고등학생 통학교통비, 초중고 수학여행비지원\r\n\r\n○ 초등학생 학원비 : 월 10만원 한도내(기초생활수급자(생계,의료))\r\n○ 중고등학생 통학교통비 : 월 3만원 정액(기초생활수급자(생계,의료))\r\n○ 초중고 수학여행비 : 30만원 한도(기초생활보장수급자(생계,의료)), 한부모가족", "지원대상": "○ 기초수급자(생계,의료급여) 및 저소득 한부모가족", "소관기관명": "경상남도 양산시", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/538000000124", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('305000000119', '동대문구 미취업청년 자격취득 활동비 지원', JSON '{"서비스ID": "305000000119", "서비스명": "동대문구 미취업청년 자격취득 활동비 지원", "서비스목적요약": "자격시험 응시자 자격취득 활동비 지원(19~39세 이하 동대문구 거주 미취업청년) ", "지원내용": "○ 미취업청년 자격취득 활동비 지원 서비스\r\n\r\n  - 지원내용 : 자격증 응시에 소요된 비용을 1인당 10만원~20만원 지급\r\n                     [동대문구사랑상품권(서울페이 플러스 app) 지급]", "지원대상": "○ 지원대상  \r\n  - 19~39세(1986~2006년생) 동대문구 거주 미취업 청년(※재학중 청년 포함) \r\n  - 2024. 11월 이후 국가(기술, 전문, 공인, 민간)자격시험, 어학시험(토익, 오픽 등 각종 어학시험), 한국사능력검정시험, 운전면허 시험 등 \r\n    자격시험에 응시한 자(※ 합격여부 무관) \r\n  - 취업여부 : 미취업자(고용보험 미가입자)만 신청 가능 \r\n    ※ 고용보험 가입되어 있더라도, 주26시간 이하 또는 3개월 이하 단기근로자는 신청 가능  \r\n○ 제외대상 : 시험접수 후 미응시자는 제외", "소관기관명": "서울특별시 동대문구", "서비스분야": "고용·창업", "신청기한": "별도공지", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/305000000119", "지원유형": "기타"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('642000000691', '강원특별자치도 차상위 긴급복지지원', JSON '{"서비스ID": "642000000691", "서비스명": "강원특별자치도 차상위 긴급복지지원", "서비스목적요약": "위기상황에 처한 가구에 생계비 등 일시적 긴급지원\r\n  * 복지부 긴급복지 지원사업 내용", "지원내용": "○ 위기가구에 생계비, 의료비, 주거비 등 일시 지원\r\n     * 복지부 긴급복지 지원사업 내용과 같음", "지원대상": "○ 소득기준(기준중위소득 75% 이하) 초과로 긴급복지 지원사업(국고) 지원을 받지 못하는 기준중위소득 85% 이하의 위기가구", "소관기관명": "강원특별자치도", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/642000000691", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('631000000124', '울산형 긴급복지 지원', JSON '{"서비스ID": "631000000124", "서비스명": "울산형 긴급복지 지원", "서비스목적요약": "저소득 위기가구에 생계, 의료, 주거 긴급지원", "지원내용": "○ 근거법률 : 긴급복지지원법 제4조, 울산광역시 저소득주민의 생활안정 지원에 관한 조례 제3조 \r\n\r\n○ 사업대상 : 위기상황에 처하여 도움이 필요한 저소득가구 중 국비 긴급복지지원사업 지원이 불가능한 자\r\n\r\n○ 지원기준 : 중위소득 80%(4인 5,196천원) 이하, 재산 2억 4,100만원 이하(주거용재산 공제한도 6,900만원), 금융재산 2,000만원 이하(주거지원은 3,000만원 이하)\r\n\r\n○ 지원내용 : 생계지원 - 1인(40만원), 2인(70만원), 3인(90만원), 4인(110만원), 의료지원 - 의료비 300만...", "지원대상": "○ 긴급한 위기사유가 발생한 가구 중 \r\n  - 정부형 긴급복지 기준 미달 가구\r\n  - 중위소득 80%이하 가구\r\n  - 재산 241백만원 이하(주거용재산 공제한도액: 69백만원)\r\n  - 금융재산 2,000만원 이하(주거비 지원시 3,000만원 이하)", "소관기관명": "울산광역시", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/631000000124", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('644000000221', '장애인 생활안정지원', JSON '{"서비스ID": "644000000221", "서비스명": "장애인 생활안정지원", "서비스목적요약": "장애인을 대상으로 장애수당, 월동비, 주거비 등 지원", "지원내용": "○ 장애수당 추가 : 장애인연금(기초, 차상위) 수급자에게 월 12,000원 지원\r\n\r\n○ 부부장애수당 : 도내 부부장애인에게 월 35,000원 지원\r\n\r\n○ 중증장애인 월동비 : 장애인연금(기초, 차상위) 및 장애아동수당(기초) 수급자에게 연간 131,000원 지원\r\n\r\n○ 월세거주 주거비 : 중위소득 80% 이하 월세거주 장애인에게 월 5만원 지원\r\n\r\n○ 장애인신문 구독 : 기초생활수급자, 차상위계층 등록장애인에게 장애인신문 지원", "지원대상": "○ 장애수당 추가 : 장애인연금 수급자 중 국민기초생활수급자 및 차상위 장애인\r\n\r\n○ 부부장애수당 : 부부가 장애인으로 등록된 세대 \r\n\r\n○ 중증장애인 월동비 : 장애인복지법에 따른 중증 장애인 중 각 호 중, 한가지에 해당하는 자\r\n   - 장애인연금 대상자 중 국민기초생활수급자 및 차상위 장애인\r\n   - 장애인아동수당 대상자 중 국민기초생활수급자\r\n\r\n○ 월세거주 주거비 : 기준중위소득 80% 이하인 월세거주 장애인가구\r\n\r\n○ 장애인신문 구독 : 국민기초생활보장법에 의한 수급자로서 등록장애인세대", "소관기관명": "충청남도", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/644000000221", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('650000000317', '청년 취업지원 희망프로젝트', JSON '{"서비스ID": "650000000317", "서비스명": "청년 취업지원 희망프로젝트", "서비스목적요약": "각 사업에 참여하는 청년을 정규직 채용시 인건비 일부 지원", "지원내용": "○ 청년취업지원희망프로젝트: 15세~39세 이하 미취업청년을 채용한 도내 중소기업(5인 미만 고용)에 1인당 월 50~70만원 최대 2년간 지원", "지원대상": "○ 청년취업지원희망프로젝트: 15세~39세이하 미취업청년을 채용한 도내 중소기업(5인 미만 고용)", "소관기관명": "제주특별자치도", "서비스분야": "고용·창업", "신청기한": "청년취업지원희망프로젝트 사업참여신청접수 - 분기별(1, 4, 7, 10월) 11~20일", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/650000000317", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('O00079500008', '소상공인 고용·산재 보험료 지원', JSON '{"서비스ID": "O00079500008", "서비스명": "소상공인 고용·산재 보험료 지원", "서비스목적요약": "부산 소상공인 대상 고용·산재보험료 기납부금액 30~50% 지원", "지원내용": "납부한 월 고용보험료의 최대 30% 5년간 지원, 납부한 월 산재보험료의 최대 50%, 5년간 지원", "지원대상": "○ 부산광역시 내 사업자 등록된 소상공인 중\r\n - 고용보험 : 자영업자 고용보험에 가입한 소상공인 중 기준보수 1~7등급인 신규 및 기존가입자\r\n - 산재보험 : 중소기업 사업주 산재보험에 가입한 소상공인 중 신규 및 기존 가입자", "소관기관명": "(재)부산경제진흥원", "서비스분야": "고용·창업", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/O00079500008", "지원유형": "현금(보험)"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('642000000712', '강원특별자치도 청년 취업준비 쿠폰 지원', JSON '{"서비스ID": "642000000712", "서비스명": "강원특별자치도 청년 취업준비 쿠폰 지원", "서비스목적요약": "도내 미취업청년에게 구직활동 지원금 지급: 월 50만원 × 6개월(1인당 최대 300만원)", "지원내용": "○ 지원내용\r\n - 청년구직활동 지원금 : 월 50만원 × 6개월(1인당 최대 300만원)\r\n\r\n○ 지원방식 : 온라인 포인트 배정 및 체크카드 사용 후 환급방식 \r\n - 카드 발급 : 지원금 전용체크카드(강원청년카드) 발급,  체크카드 우선 지출 → 사용 승인 신청 → 검토 및 승인 → 포인트 차감 → 사용금액 환급\r\n - 포인트 지급 : 1인당 매월 50만 포인트 배정(매월 1일), 복지몰(현대이지웰) 연계상품 포인트로 결제, 포인트 즉시 차감", "지원대상": "○ 공고일 기준 강원특별자치도 거주, 최종학력 기준 졸업(중퇴), 만18세~45세이하 미취업 청년\r\n -최근 3개월 가구소득액 평균이 기준중위소득 120%초과 ~ 180%이하(만18세~34세 이하), 기준중위소득 180%이하(만35세~45세 이하)", "소관기관명": "강원특별자치도", "서비스분야": "고용·창업", "신청기한": "2025년 3~6월", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/642000000712", "지원유형": "이용권"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('149200005027', '생활안정자금(융자)(이차보전)', JSON '{"서비스ID": "149200005027", "서비스명": "생활안정자금(융자)(이차보전)", "서비스목적요약": "개인 신용 대출금리에서 3.0% 이내 보전", "지원내용": "ㅇ 결혼, 자녀 양육 등 생활자금이 부족한 노동자 등에게 생활안정자금 융자(개인 신용 대출금리에서 3.0% 이내 보전)\r\n\r\n  - 중위소득 이하자(3인가구 기준): 1인당 총 2,000만 원(생활안정자금(융자) 한도와 별도)", "지원대상": "① 혼례비,  ② 자녀양육비,  ③ 노부모부양비, ④장례비\r\n\r\n  -  3개월 이상 근속 중인 노동자, 특수형태근로종사자, 중소기업 사업주 산재보험 임의 가입한 1인 자영업자\r\n  - 월평균 소득이 중위소득(3인 가구) 이하", "소관기관명": "고용노동부", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/149200005027", "지원유형": "현금(융자)"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('PTR000050831', 'K-Move스쿨(해외취업연수사업)', JSON '{"서비스ID": "PTR000050831", "서비스명": "K-Move스쿨(해외취업연수사업)", "서비스목적요약": "해외취업 지원을 위한 연수 프로그램 개설 및 교육 실시 해외취업 연계\r\n", "지원내용": "○ 국내·외 우수 교육훈련기관을 활용, 구인기업이 요구하는 어학 및 직무능력, 생활문화 등에 대한 맞춤형 연수과정 제공 후 해외취업 연계\r\n - 연수비 지원(일부 자부담)\r\n - 한국산업인력공단이 직접 연수를 실시하지 아니하고 외부 전문 연수기관을 선정하여 연수과정 운영", "지원대상": "○ 대한민국 국민으로서 아래 요건 어느 하나에 해당하는 자\r\n - 만 15~34세 이하로 해외취업에 결격사유가 없는 자(30% 범위 내에서 연령 초과하여 모집 가능)\r\n  * 단, 군 복무자에 대하여 군 복무기간 1년 미만은 1세, 1년 이상 2년 미만은 2세, 2년 이상은 3세의 상한연령을 연장함\r\n - 구인업체가 요구한 채용조건에 부합하는 자\r\n - 최종학교(대학교 이하)의 졸업자 또는 최종학년인 자로 연수과정 종료 후 졸업 및 해외취업이 가능한 자", "소관기관명": "고용노동부", "서비스분야": "고용·창업", "신청기한": "접수기관 별 상이", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/PTR000050831", "지원유형": "서비스(일자리)"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('626000000148', '부산형 긴급복지지원 사업', JSON '{"서비스ID": "626000000148", "서비스명": "부산형 긴급복지지원 사업", "서비스목적요약": "위기상황에 처해 도움이 필요한가구에게 신속하고 단기간 생계비를 지원하는 사업", "지원내용": "긴급생계비(원칙1회, 최대3회)   * 1인가구 780,000원(가구원수별 차등 지급)", "지원대상": "갑작스러운 아래 위기상황 발생으로 생계유지가 곤란한 가구 \r\n \r\n○ 위기사유\r\n  • 주소득자가 사망, 가출, 행방불명, 구금시설에 수용되는 등의 사유로 소득을 상실한 경우\r\n  • 중한 질병 또는 부상을 당한 경우\r\n  • 가구구성원으로부터 방임 또는 유기되거나 학대 등을 당한 경우 \r\n  • 가정폭력 또는 가구구성원으로부터 성폭력을 당한 경우 \r\n  • 화재 또는 자연재해 등으로 거주하는 주택(건물)에서 생활하기 곤란하게 된 경우 \r\n  • 주소득자 또는 부소득자의 휴폐업 또는 사업장의 화재 등으로 인하여 실질적인 영업이 곤란...", "소관기관명": "부산광역시", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/626000000148", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('SBA000000100', '자활근로(기초, 차상위)', JSON '{"서비스ID": "SBA000000100", "서비스명": "자활근로(기초, 차상위)", "서비스목적요약": "수급자 및 저소득층 참여자에게 자활근로 일자리 제공, 인건비 지급 등", "지원내용": "\"근로능력 정도에 따라 유형별 자활사업단에 참여하도록 직접 일자리 지원\r\n\r\n○ 시장진입형: 1일 8시간, 주 5일, 66,080원/일\r\n\r\n○ 사회서비스형: 1일 8시간, 주 5일, 57,840원/일\r\n\r\n○ 근로 유지형: 1일 5시간, 주 5일, 33,940원/일", "지원대상": "1) 지원대상\r\n조건부 수급자, 자활특례자, 일반 수급자 중 희망자(근로 능력 무관), 차상위계층, 전문기술보유자 등\r\n○ 조건부 수급자: 자활사업 참여를 의무 조건으로 생계급여를 받는 수급자\r\n○ 일반 수급자 : 근로 능력 없는 생계급여수급권자 및 조건부과제외자, 의료·주거·교육급여수급권자 중 참여희망자\r\n○ 자활급여특례자: 생계·의료급여 수급자가 자활사업(자활기업·국민취업지원제도 포함)에 참여하여 발생한 소득으로 인하여 소득인정액이 기준 중위소득의 40%를 초과한 경우\r\n○ 차상위계층 등 : 근로 능력이 있고, 소득인정액이 기준...", "소관기관명": "보건복지부", "서비스분야": "고용·창업", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/SBA000000100", "지원유형": "서비스(일자리)"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('B11005300003', '기초생활(생계·의료)수급자 TV수신료 면제', JSON '{"서비스ID": "B11005300003", "서비스명": "기초생활(생계·의료)수급자 TV수신료 면제", "서비스목적요약": "TV수신료 면제대상이 면제신청을 한 달부터 TV수신료 면제 적용", "지원내용": "○ TV수신료 면제 \r\n\r\n - 방송법시행령 제44조 제1항 1호에 규정된 면제 대상자가 접수기관에 TV수신료 면제를 신청한 달부터 면제 적용\r\n\r\n    (자격취득일부터 적용되는 것이 아님에 주의)\r\n\r\n - TV수신료 월 2,500원 면제", "지원대상": "○ 면제대상 (TV수상기 소지자에 한하며, 영업을 목적으로 한 공간에 설치한 수상기는 제외)\r\n\r\n - 국민기초생활 보장법 제7조제1항제1호에 따른 생계급여의 수급자 또는 같은 항 제3호에 따른 의료급여 수급자", "소관기관명": "한국방송공사", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/B11005300003", "지원유형": "현금(감면)"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('320000000112', '기초생활수급자 명절위문금 지원', JSON '{"서비스ID": "320000000112", "서비스명": "기초생활수급자 명절위문금 지원", "서비스목적요약": "○ 기초생활수급자(생계·의료) 명절위문품비 지급", "지원내용": "○ 기초생활수급자(생계·의료) 명절위문품비 지급\r\n   - 지원시기: 설, 추석 연 2회 가구당 각 40,000원 지급\r\n   - 지급방법: 해당 지급일에 수급자의 계좌에 입금", "지원대상": "○ 기초 생계·의료급여 수급자 가구당 지원\r\n   - 입양대상아동 및 시설수급자 제외", "소관기관명": "서울특별시 관악구", "서비스분야": "생활안정", "신청기한": "신청 불필요", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/320000000112", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('333000000376', '해운대구 무의탁 노인세대 지원', JSON '{"서비스ID": "333000000376", "서비스명": "해운대구 무의탁 노인세대 지원", "서비스목적요약": "저소득층 독거노인에게 명절 위로금 및 경로의 달 격려금 지원", "지원내용": "○ 무의탁 독거노인세대 명절위로금\r\n - 대상 : 기초생활수급자(생계,의료) 무의탁 독거노인\r\n - 지원 : 명절 위로금 5만원\r\n\r\n○ 저소득층 독거노인 명절 위로금\r\n - 대상 : 65세 이상 차상위, 저소득층 독거노인\r\n - 지원 : 명절 위로금 2만원\r\n\r\n○ 경로의달 무의탁 노인세대 격려\r\n - 대상 : 차상위,저소득층 무의탁 독거노인세대\r\n - 지원 :  위로금 2만원", "지원대상": "○ 무의탁 독거노인세대 명절위로금\r\n- 기초생활수급자무의탁 독거노인\r\n\r\n○ 저소득층 독거노인 명절위로금\r\n- 65세이상 차상위계층, 저소득 독거노인\r\n\r\n○ 경로의 달 무의탁 노인세대 격려\r\n- 65세이상 차상위계층, 저소득 무의탁 독거노인", "소관기관명": "부산광역시 해운대구", "서비스분야": "생활안정", "신청기한": "신청불필요", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/333000000376", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('149200000081', '장애인 인턴제', JSON '{"서비스ID": "149200000081", "서비스명": "장애인 인턴제", "서비스목적요약": "장년, 발달장애인 및 고용이 현저히 어려운 특정 유형의 중증장애인을 인턴채용시 지원", "지원내용": "○ 인턴 채용 사업주 지원금\r\n\r\n - 인턴지원금: 약정임금의 80%지원, 최대 월 100만 원, 인턴기간 최대 6개월\r\n\r\n - 정규직 전환지원금: 인턴 종료 후 정규직 전환 시 약정임금의 80% 지원, 최대 월 80만 원", "지원대상": "○ 중증장애인 평균 고용률 이하 8개 장애유형 및 발달장애\r\n\r\n - 시각, 뇌병변, 정신, 신장, 언어, 호흡기, 뇌전증, 척수손상 또는 근육병증으로 운동기능 장애가 있는 지체 등 \r\n - 발달(지적, 자폐성)\r\n\r\n\r\n○ 만 50세 이상 중증 또는 경증 장애인", "소관기관명": "고용노동부", "서비스분야": "고용·창업", "신청기한": "수시신청(예산소진시까지)", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/149200000081", "지원유형": "서비스(일자리)"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('149200000032', '장애인 직업 능력 개발 지원', JSON '{"서비스ID": "149200000032", "서비스명": "장애인 직업 능력 개발 지원", "서비스목적요약": "15세 이상 구직장애인에게 직업능력개발 훈련비 등 지원", "지원내용": "○ 장애인공단 훈련 : 훈련생 훈련수당 지원\r\n○ 공공훈련 기관: 훈련생 훈련수당 및 교사 수당 지원 \r\n○ 민간훈련 기관: 훈련생 훈련수당 및 훈련 기관 훈련비 지원", "지원대상": "○ 직업훈련을 희망하는 15세 이상 등록 구직 장애인", "소관기관명": "고용노동부", "서비스분야": "고용·창업", "신청기한": "○ 장애인공단: 수시신청 ○ 공공훈련 기관: 매월 훈련 실시 후 10일 이내 ○ 민간훈련 기관: 매월 훈련 실시 후 10일 이내", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/149200000032", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('O00005900002', '수도요금 감면(기초생활수급자)', JSON '{"서비스ID": "O00005900002", "서비스명": "수도요금 감면(기초생활수급자)", "서비스목적요약": "국민기초생활수급 가구에게 월 최대 10톤 분량의 수도요금 감면", "지원내용": "○ 기초생활수급자 가구에 대해 가정용 수도요금 감면\r\n - 가정용 수도 월 사용량에서 최대 10톤에 해당하는 요금을 감면(월 사용량이 10톤 미만일 경우 기본요금만 부과)", "지원대상": "○ 국민기초생활수급자\r\n - 「국민기초생활 보장법」에 따른 수급자\r\n -  차상위계층은 해당대상 아님", "소관기관명": "경기도 남양주시", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/O00005900002", "지원유형": "현금(감면)"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('149200005019', '중증장애인근로자 출퇴근 비용 지원', JSON '{"서비스ID": "149200005019", "서비스명": "중증장애인근로자 출퇴근 비용 지원", "서비스목적요약": "○ 지원내용: 매월 7만원 한도로 교통 실비 지원(전용카드 발급 필수)\r\n", "지원내용": "○ 지원내용: 매월 7만원 한도로 교통 실비 지원(전용카드 발급 필수)\r\n○ 지원범위: 대중교통(버스, 지하철), 택시(장애인콜택시포함), 유류비 등", "지원대상": "○ 최저임금적용제외인가를 받은 중증장애인 근로자 또는 국민기초생활수급·차상위계층인 중증장애인 근로자", "소관기관명": "고용노동부", "서비스분야": "고용·창업", "신청기한": "수시신청(예산소진시까지)", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/149200005019", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('O00112500006', '천안시 긴급지원 대상자 특별 지원 사업', JSON '{"서비스ID": "O00112500006", "서비스명": "천안시 긴급지원 대상자 특별 지원 사업", "서비스목적요약": " 재해 재난 및 기타 다양한 사유로 매우 긴급한 위기에 처한 위기 취약계층 긴급 지원", "지원내용": "1. 지원목적 : 재해 재난 및 기타 다양한 사유로 매우 긴급한 위기에 처한 위기 취약계층 지원\r\n2. 지원기준 : 기초 생활 수급자 / 차상위 계층 대상자 / 한부모가족 대상자 / 2026년 건강보험료 납부기준 130% 이하\r\n3. 지원금액 : 천안시 취약계층 지원사업 배분 기준 및 본 재단 심의 결정 금액", "지원대상": "o 기초 생활 수급자 / 차상위 계층 대상자 / 한부모가족 대상자 / 2025년 건강보험료 납부기준 130% 이하\r\n\r\no 천안시청 및 읍면동 행정복지센터, 사회복지기관, 시설 및 단체에서 발굴 및 추천한 복지 사각지대 중 재단 심의 의결 통과 대상", "소관기관명": "천안복지재단", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/O00112500006", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('142100000015', '장애인 창업점포 지원사업', JSON '{"서비스ID": "142100000015", "서비스명": "장애인 창업점포 지원사업", "서비스목적요약": "○ 부동산 임차 보증금(1억 3천만원 한도 내 최대 5년간 지원)", "지원내용": "○ 부동산 임차 보증금(1억 3천만원 한도 내 최대 5년간 지원)", "지원대상": "○ 장애인 예비창업자, 업종전환 희망 장애인기업", "소관기관명": "중소벤처기업부", "서비스분야": "고용·창업", "신청기한": "3월", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/142100000015", "지원유형": "기타"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('304000000131', '저소득 위기가정 지원', JSON '{"서비스ID": "304000000131", "서비스명": "저소득 위기가정 지원", "서비스목적요약": "생계가 곤란한 가정에게 생계비,주거비,교육비 등 제공", "지원내용": "생계비, 주거비, 교육비 등 (희망온돌 따뜻한 겨울나기 성금 활용)", "지원대상": "중위소득 120% 이내 가구 중 생계 곤란으로 지원이 필요하다고 인정되는 가구", "소관기관명": "서울특별시 광진구", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/304000000131", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('135200005027', '일상돌봄 서비스', JSON '{"서비스ID": "135200005027", "서비스명": "일상돌봄 서비스", "서비스목적요약": "필요에 맞게 기본서비스(재가돌봄, 가사)와 특화서비스(식사영양 등)를 선택적 조합하여 이용", "지원내용": "대상자로 선정되면 필요에 맞게 서비스를 선택해 지자체에서 이용권(바우처)을 발급받은 후, 제공기관에서 서비스 이용\r\n○ 기본서비스(24·36·72시간) 및 특화서비스(최대 2개)를 조합하여 이용 가능\r\n  - 기본서비스는 재가 돌봄(세면 등 신체청결, 옷 갈아입히기 등 몸단장 지원, 식사도움, 체위변경, 안전관리 등 신체 수발지원 및 건강지원 등), 가사 지원(청소, 세탁, 식사 준비 등 가정 내 일상생활을 위한 가정환경 마련) 제공\r\n○ 특화서비스는 식사영양관리 서비스 등 11종을 제공\r\n  - 식사관리 서비스 :  질환 등으로 ...", "지원대상": "<돌봄 필요 청·중장년>\r\n①일상생활에 돌봄이 필요한 청·중장년(13~64세)\r\n②질병, 부상 등으로 일상 생활에 어려움이 있는 자(진단서·소견서·장기요양인정서·근로능력판정결과서 등 또는 공공·민간기관의 추천서)\r\n③돌봄을 수행할 가족 등이 없는 자(주민등록상 1인 가구 또는 2인 가구이나 경제활동·장기 부재 등의 사유로 가구원 돌봄이 불가한 자)\r\n\r\n * 위 세가지 조건을 모두 충족할 것\r\n\r\n<가족돌봄청년>\r\n①가족을 돌보는 청년(39세 이하)\r\n②동거하는 가족의 질병, 부상 등으로 돌봄 필요성이 있는 자(진단서·소견서·장기요...", "소관기관명": "보건복지부", "서비스분야": "생활안정", "신청기한": "접수기관 별 상이", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/135200005027", "지원유형": "이용권"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('629000000111', '광주형기초생활보장', JSON '{"서비스ID": "629000000111", "서비스명": "광주형기초생활보장", "서비스목적요약": "○ 전남광주통합특별시 거주자 중 법정지원을 받지 못하는 저소득 세대에 생계, 해산, 장제급여 지원", "지원내용": "○ 법정지원을 받지 못하는 광주시 거주 저소득층 대상으로 기본적인 생활 유지에 필요한 현금급여 지원\r\n\r\n○ 지원내용 : 생계급여(정액급여), 해산급여, 장제급여", "지원대상": "○ 사업대상 : 법정지원을 받지 못하는 생활이 어려운  저소득 광주 거주 시민\r\n\r\n○ 선정기준 : (소득) 기준중위소득 50% 이하, (재산) 1억6천만원 이하(금융재산 3천만원 이하), \r\n                       (부양의무자) 연 1.3억원, 일반재산 12억원(부양의무자 소득 및 재산 기준 초과 시 광주형 기초보장 대상에서 제외)", "소관기관명": "전남광주통합특별시", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/629000000111", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('142100000014', '장애인기업확인서 발급', JSON '{"서비스ID": "142100000014", "서비스명": "장애인기업확인서 발급", "서비스목적요약": "장애인기업 확인서 발급", "지원내용": "장애인기업 확인서 발급", "지원대상": "○ 장애인기업활동촉진법 2조 2호 기준 해당 기업", "소관기관명": "중소벤처기업부", "서비스분야": "고용·창업", "신청기한": "연중수시", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/142100000014", "지원유형": "기타"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('374000000145', '기초생활보장 생계급여', JSON '{"서비스ID": "374000000145", "서비스명": "기초생활보장 생계급여", "서비스목적요약": "생계급여 수급자에게 기초(기본)생활 보장을 위한 생계급여 지급", "지원내용": "○ 지원대상 : 소득인정액이 기준중위소득 32% 이하이면서 고소득.고재산 부양의무자가 없는 생계급여 수급자\r\n\r\n○ 지원내용 : 기준 중위소득 32%에 해당하는 금액과 가구의 소득인정액과의 차액을 가구 단위로 매월 지급\r\n - 의복, 음식물 및 연료비, 기타 일상생활에 기본적으로 필요한 금품 지급\r\n\r\n○ 지원금액 : 1인가구 기준 최대 820,556원 지원, 4인가구 기준 최대 2,078,316원 지급\r\n - (예) 소득인정액이 300,000원인 1인가구 생계급여 수급자 가구에 생계급여 월 지급액은 520,556원", "지원대상": "○ 소득인정액이 기준중위소득 32% 이하이면서 고소득.고재산 부양의무자가 없는 생계급여 수급자", "소관기관명": "경기도 수원시", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/374000000145", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('315000000108', '저소득시민 명절위문품비 지원', JSON '{"서비스ID": "315000000108", "서비스명": "저소득시민 명절위문품비 지원", "서비스목적요약": "국민기초생계 또는 의료급여 수급자 가구에 명절위문품비 지원", "지원내용": "○ 연 2회 기초생계 또는 기초의료수급자 가구에 시비 3만원 구비 2만원 총 5만원 지원", "지원대상": "○ 국민기초생계 또는 의료급여 수급자 가구", "소관기관명": "서울특별시 강서구", "서비스분야": "생활안정", "신청기한": "명절 전 구청에서 일괄 수행", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/315000000108", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('629000000147', '위기가구발굴단 및 복지1촌', JSON '{"서비스ID": "629000000147", "서비스명": "위기가구발굴단 및 복지1촌", "서비스목적요약": "○ 위기상황에 처한 가구에 사회복지서비스 연계,  복지1촌 결연 등", "지원내용": "○ 위기가구발굴단 운영을 통한 복지사각지대 위기가구발굴 및 지원(1촌 맺기 등)\r\n - 기초생활보장제도, 긴급복지, 광주형기초보장지원사업, 노랑호루라기지원사업 등 공적 서비스 연계\r\n - 기타 민간자원 등 사회복지서비스 지원", "지원대상": "○ 소득감소, 실직 등으로 생계곤란 가구\r\n○ 쪽방, 고시원, 여인숙 등에 거주하는 주거취약가구\r\n○ 가정폭력, 아동학대 등에 노출 또는 그럴 우려가 높은 가구\r\n○ 독거 어르신, 장애인, 취약아동 등 돌봄취약가구\r\n○ 중대한 질병, 장애 등 건강문제로 도움이 필요한 가구 등", "소관기관명": "전남광주통합특별시", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/629000000147", "지원유형": "서비스(돌봄)"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('390000000127', '광명시 노인 대중교통비 지원', JSON '{"서비스ID": "390000000127", "서비스명": "광명시 노인 대중교통비 지원", "서비스목적요약": "광명시 노인을 대상으로 연간 16만원 한도 대중교통비 지원 (분기당 최대 4만원)", "지원내용": "광명시 노인을 대상으로 연간 16만원 한도 대중교통비 지원 (분기당 최대 4만원)", "지원대상": "❍ 대상 : 광명시 거주 노인(만65세 이상,대한민국 국적자)\r\n※ 주민등록주소 기준이며, 소득 등 다른 기준·요건 없음\r\n※ 기초생활수급자, 차상위계층인 경우 지원금이 소득으로 산정되므로 카드 발급 전 주민센터(사회복지담당자) 방문 후 결정필요\r\n※ 국가유공자인 경우 교통비혜택을 받고 있으므로 지패스카드 신청시 국가유공자 교통비 혜택 없음", "소관기관명": "경기도 광명시", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/390000000127", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('135200005026', '긴급돌봄 지원', JSON '{"서비스ID": "135200005026", "서비스명": "긴급돌봄 지원", "서비스목적요약": "일시적 위기상황에 대응하기 위한 한시적 재가 방문형 돌봄·가사 및 이동지원 서비스 제공", "지원내용": "○ 일시적 위기상황에 대응하기 위한 한시적 재가 방문형 돌봄·가사 및 이동지원 및 방문목욕 서비스 제공\r\n  * 방문목욕은 일부 시·도에서 제공 중이며, 현장방문 결과와 상관없이 본인이 희망하는 경우 서비스를 제공받을 수 있음 (서비스 제공기간 내 최대 4회)\r\n  - (내용) 일정 자격을 갖춘 서비스 제공인력이 대상자의 가정을 방문해 기본돌봄 서비스(재가 돌봄, 가사·이동 지원) 및 방문목욕 서비스를 제공\r\n  - (시간) 최대 72시간의 범위 내에서 지원하며, 가급적 30일 이내에 사용을 권고\r\n   * 자세한 사항은 지자체(읍...", "지원대상": "주 돌봄자 부재, 질병, 부상 등으로 긴급하고 일시적 돌봄 지원이 필요하나 기존 서비스로 돌봄을 받기 어려운 국민", "소관기관명": "보건복지부", "서비스분야": "생활안정", "신청기한": "지자체별 상이", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/135200005026", "지원유형": "서비스(돌봄)"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('401000000103', '노인일자리 지원', JSON '{"서비스ID": "401000000103", "서비스명": "노인일자리 지원", "서비스목적요약": "기초연금 및 직역연금 수급자에게 공익형 노인일자리사업 연계", "지원내용": "○ 노인공익활동 노인일자리사업 참여자에게 활동비 지급 (26년 기준 월 290천원)\r\n - 근무시간 : 월 30시간 (일 3시간 이내)\r\n\r\n○ 노인역량활용 노인일자리사업 참여자에게 활동비 지급 (26년 기준 월 634천원)\r\n - 근무시간 : 월 60시간 (주 15시간 이내)\r\n\r\n○ 공동체사업단 노인일자리사업 참여자에게 활동비 지급 (근로계약에 따라 다름)", "지원대상": "○ 만 65세 이상 기초연금 대상자 중 선발(일부 만60세)\r\n○ 제외대상 \r\n  - 국민기초생활보장법에 의한 생계급여 수급자\r\n  - 정부부처 및 지자체에서 추진하는 일자리사업에 3개이상 참여하고 있는자\r\n  - 장기요양보험 등급판정자(1~5등급, 인지지원등급)", "소관기관명": "경기도 시흥시", "서비스분야": "고용·창업", "신청기한": "노인일자리 모집기간", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/401000000103", "지원유형": "서비스(일자리)"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('O00012200001', '마포형 위기가구 지원', JSON '{"서비스ID": "O00012200001", "서비스명": "마포형 위기가구 지원", "서비스목적요약": "저소득주민 대상 생계비, 의료비, 주거비 등 경제적 지원 제공", "지원내용": "○ 경제적 위기를 겪는 저소득 주민 지원\r\n - 긴급생계비\r\n - 의료비\r\n - 단전·단수/가스끊김/건강보험체납비\r\n - 주거지원비\r\n - 주거환경개선 지원비\r\n - 재난재해 긴급지원비\r\n\r\n ※별도의 내부 심의를 거쳐 지원 대상자 최종 선정", "지원대상": "소득인정액이 기준중위소득 120% 이하", "소관기관명": "마포복지재단", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/O00012200001", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('307000000110', '저소득구민 명절 위문금 지급 (차상위 아동·청소년 가구)', JSON '{"서비스ID": "307000000110", "서비스명": "저소득구민 명절 위문금 지급 (차상위 아동·청소년 가구)", "서비스목적요약": "동주민센터 추천을 받은 차상위 아동·청소년 250가구에 100,000원 지급", "지원내용": "지원대상\r\n- 차상위 아동·청소년 250가구\r\n\r\n지원내용\r\n- 초·중·고 자녀 학용품비 가구당 100,000원 지원\r\n\r\n지원시기\r\n설, 추석 명절\r\n\r\n지원방법\r\n- 동주민센터 추천 명단 수합 후 수급자의 계좌에 입금", "지원대상": "동주민센터 추천을 받은 차상위 아동·청소년 250가구", "소관기관명": "서울특별시 성북구", "서비스분야": "생활안정", "신청기한": "신청불필요", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/307000000110", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('138300000052', '청소년 미혼 한부모 자립지원 (우리원더패밀리)', JSON '{"서비스ID": "138300000052", "서비스명": "청소년 미혼 한부모 자립지원 (우리원더패밀리)", "서비스목적요약": "청소년 미혼 한부모(미혼모, 미혼부) 생활비 등 지원", "지원내용": "(필수)청소년 미혼 한부모(미혼모, 미혼부)에게 매월 생활비 50만원 지원\r\n(선택)  긴급 의료비, 교육/취업 축하 · 격려금", "지원대상": "대한민국 국적의 24세 이하 미혼 한부모 및 임산부\r\n   - (1순위) 19세 이하 청소년 미혼 한부모(소득 무관, 전원 지원)\r\n   - (2순위) 20세 이상 24세 이하 청소년 미혼 한부모(중위소득 50%이하)", "소관기관명": "성평등가족부", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/138300000052", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('313000000104', '저소득 주민 특별생계 보호', JSON '{"서비스ID": "313000000104", "서비스명": "저소득 주민 특별생계 보호", "서비스목적요약": "일시적 지원이 필요한 저소득 주민에게 특별생계비, 건강보험료 등 지원", "지원내용": "○ 지원대상 : 갑작스러운 질병 및 사고로 인해 생활이 어려워 일시적인 지원이 필요한 저소득 주민\r\n\r\n○ 지원내용\r\n - 특별생계비 : 2026년 기준중위소득의 15%에 해당하는 금액(최대지원 금액)\r\n  ㆍ1인 기준 384,000원, 2인기준 629,000원, 3인기준 803,000원, 4인 기준974,000원, 5인기준 1,133,000원, 6인기준 1,283,000원, 7인기준 1,427,000원\r\n  ㆍ8인 이상 가구의 지급기준 : 1인 증가시마다 143,000원을 7인가구 기준에 더하여 산정\r\n - 건강보험료 및 공공요금...", "지원대상": "○ 소득 및 재산 기준\r\n - 소득인정액 기준중위소득 70% 이하\r\n - 재산 1억3천5백만원 이하", "소관기관명": "서울특별시 마포구", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/313000000104", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('397000000113', '노인생활안정 지원', JSON '{"서비스ID": "397000000113", "서비스명": "노인생활안정 지원", "서비스목적요약": "관내 거주하는 노인을 대상으로 장수수당, 장수축하금 등 지원", "지원내용": "○ 장수수당 : 관내에서 6개월 이상 연속 거주하고 있는 만 80세 이상 장수 노인에 대해 신청한 달부터 월 3만원씩 지급 \r\n\r\n○ 장수축하금 : 관내에서 1년 이상 연속 거주하고 있는 만 90세 이상  장수 어르신에게 생애 1회 100만원을 현금으로 지급\r\n\r\n○ 저소득 노인 사회활동 장려금 : 3년 이상 관내에 계속 주소를 두고 거주하는 만75세 이상 기초생활보장수급자 및 차상위 대상자에게 매월 5만원을 지역화폐로 지급", "지원대상": "○ 장수수당 : 만 80세 이상 관내에서 6개월 이상 연속 거주하고 있는 장수 노인\r\n\r\n○ 장수축하금 : 관내에서 1년 이상 연속 거주하고 있는 만 90세 이상  장수 어르신\r\n\r\n○ 저소득 노인 사회활동 장려금 : 3년 이상 관내에 계속 주소를 두고 거주하는 만75세 이상 기초생활보장수급자 및 차상위 대상자", "소관기관명": "경기도 과천시", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/397000000113", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('142000000090', '장애인 기업 시제품제작 지원', JSON '{"서비스ID": "142000000090", "서비스명": "장애인 기업 시제품제작 지원", "서비스목적요약": "장애인 및 기업에게 제품디자인 및 시제품모형제작에 소요되는 비용 일부 지원", "지원내용": "○ (제품디자인 및 시제품모형제작) 기업규모에 따라 70%~90% 이내, 최대 1,500만원\r\n\r\n○ (시제품금형제작) 기업규모에 따라 70%~90% 이내, 최대 2,500만원", "지원대상": "○ 장애인 예비창업자, 장애인기업", "소관기관명": "중소벤처기업부", "서비스분야": "고용·창업", "신청기한": "3월~4월", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/142000000090", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('418000000240', '춘천형 위기가구 생활안정 지원', JSON '{"서비스ID": "418000000240", "서비스명": "춘천형 위기가구 생활안정 지원", "서비스목적요약": "위기가구에 의료비, 간병비, 생계비 등 지원", "지원내용": "○ 갑작스런 응급상황에 처한 위기, 욕구별 맞춤서비스 지원\r\n - 의료비, 간병비, 생계비, 난방비, 주거수리비, 체납공과금 등", "지원대상": "○ 춘천시 관내(주민등록)거주지로 기준 중위소득120%이하, 재산1억5,200만원 이하, 금융800만원 이하 가구", "소관기관명": "강원특별자치도 춘천시", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/418000000240", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('310000000119', '한부모가족 지원', JSON '{"서비스ID": "310000000119", "서비스명": "한부모가족 지원", "서비스목적요약": "미혼 한부모, 한부모가족 등에게 냉·난방비 지원", "지원내용": "○ 미혼한부모 냉방비, 난방비 지원\r\n - 냉방비(8월, 9월), 난방비(11월, 12월) 지원되며 가구당 1회 30천원씩 4회 지원\r\n  * 타 사업과 중복지원인 경우 제외\r\n\r\n○ 한부모가족복지시설 입소자 명절위문금 지원\r\n - 설, 추석 명절위문금 1인당 3만원 지원(시비 1만원, 구비 2만원)", "지원대상": "○ 미혼한부모 냉방비,난방비 지원\r\n - 법정 미혼 한부모가족\r\n\r\n○ 한부모가족복지시설 입소자 명절위문금 지원\r\n - 한부모가족복지시설 입소 중인 한부모가족", "소관기관명": "서울특별시 노원구", "서비스분야": "생활안정", "신청기한": "신청 불필요", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/310000000119", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('309000000135', '저소득주민 명절 위문품비 지급', JSON '{"서비스ID": "309000000135", "서비스명": "저소득주민 명절 위문품비 지급", "서비스목적요약": "저소득주민에게 명절 위문품비 지원", "지원내용": "○ 명절(설, 추석)에 기초생계급여수급자 가구 또는 기초의료급여수급자 가구에 가구당 2만원씩 지급\r\n ※ 가구별 지급이며,  입양아동 및 시설수급자는 제외", "지원대상": "○ 기초생계급여수급자 가구, 기초의료급여수급자 가구 (※시설 수급자 제외)", "소관기관명": "서울특별시 도봉구", "서비스분야": "생활안정", "신청기한": "접수기관 별 상이", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/309000000135", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('303000000107', '저소득장애인 명절위문금 지원', JSON '{"서비스ID": "303000000107", "서비스명": "저소득장애인 명절위문금 지원", "서비스목적요약": "차상위 장애인 등에게 명절위문금 지원", "지원내용": "○ 차상위 등 저소득 장애인에게 연 2회(설, 추석) 1인 3만원 지급", "지원대상": "○ 차상위 장애인, 장애인 일자리 참여자 등", "소관기관명": "서울특별시 성동구", "서비스분야": "생활안정", "신청기한": "신청불필요", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/303000000107", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('403000000147', '노인 버스 무료승차 지원', JSON '{"서비스ID": "403000000147", "서비스명": "노인 버스 무료승차 지원", "서비스목적요약": " 의왕시 정차, 시내, 마을, 광역 버스 요금(환승비포함) 지원(시원, 공항버스 제외)\r\n", "지원내용": "○대상: 65세이상 의왕시 거주 시민( 해당년도 생일 지나신 분)\r\n○지원내용: 의왕시 정차, 시내, 마을, 광역 버스 요금(환승비포함) 지원(시원, 공항버스 제외)\r\n○지원금액: 연간 20만원(분기별 5만원)\r\n○ 지원방법: 충전 선불 교통카드 이용 ⇒ 분기별 실사용료 현금 지급\r\n○ 신청기간: 상시발급", "지원대상": "65세이상 의왕시 거주 노인(해당년도 생일 지나신 분)", "소관기관명": "경기도 의왕시", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/403000000147", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('314000000116', '저소득 한부모가정 명절위문금 지급', JSON '{"서비스ID": "314000000116", "서비스명": "저소득 한부모가정 명절위문금 지급", "서비스목적요약": "저소득 한부모가정에 명절 위문금 지급", "지원내용": "○ 설날 및 추석 연 2회 가구당 4만원 명절위문금 지급", "지원대상": "○ 저소득한부모가정", "소관기관명": "서울특별시 양천구", "서비스분야": "생활안정", "신청기한": "신청불필요", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/314000000116", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('554000000163', '돌봄 취약가구 반려동물 의료서비스 등 지원', JSON '{"서비스ID": "554000000163", "서비스명": "돌봄 취약가구 반려동물 의료서비스 등 지원", "서비스목적요약": " - (의료지원) 백신접종비, 중성화수술비, 기본검진 및 치료비(수술 포함) 등\r\n", "지원내용": "○ 지원금액: 마리당 최대 20만원(본인부담금 20%(4만원) 포함)\r\n○ 지원내용\r\n - (의료지원) 백신접종비, 중성화수술비, 기본검진 및 치료비(수술 포함) 등\r\n - (돌봄지원) 반려동물 돌봄위탁비(최대 10일이내)", "지원대상": "관내 반려동물을 기르는 돌봄 취약가구\r\n -  중증장애인\r\n -  저소득가구\r\n -  한부모가정\r\n -  다문화가정\r\n -  저소득 1인가구", "소관기관명": "경기도 광주시", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/554000000163", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('307000000117', '저소득구민 명절 위문금 지급 (기초 생계·의료급여 수급자)', JSON '{"서비스ID": "307000000117", "서비스명": "저소득구민 명절 위문금 지급 (기초 생계·의료급여 수급자)", "서비스목적요약": "기초 생계·의료급여 수급자 가구에 50,000원 지급", "지원내용": "지원 대상\r\n- 기초 생계·의료급여 수급자(시설수급자 제외) \r\n지원내용\r\n- 명절위문금 가구당 50,000원(시비 30,000원 + 구비 20,000원)\r\n지원기준일 \r\n- 설, 추석 명절\r\n지원방법\r\n- 동별 명단 수합 후 수급자의 계좌에 현금 입금", "지원대상": "기초 생계·의료급여 수급자 가구(시설수급자 제외)", "소관기관명": "서울특별시 성북구", "서비스분야": "생활안정", "신청기한": "신청불필요", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/307000000117", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('536000000112', '아이돌봄서비스 본인부담금 지원', JSON '{"서비스ID": "536000000112", "서비스명": "아이돌봄서비스 본인부담금 지원", "서비스목적요약": "맞벌이 등의 가정을 위해 아이돌봄서비스 이용 시 본인부담금 차등 지원 ", "지원내용": "○ 맞벌이 등 양육공백 가정의 자녀가 아이돌봄서비스를 이용할 경우, 본인부담금 차등지원 - 첫째아 최대 50% 둘째아 최대 70%, 셋째아 이상 최대 100%", "지원대상": "○ 밀양시 거주, 12세 이하 양육공백이 발생하여 아이돌봄서비스를 이용하는 가정", "소관기관명": "경상남도 밀양시", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/536000000112", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('393000000108', '노인 목욕 및 이·미용 바우처 사업 지원', JSON '{"서비스ID": "393000000108", "서비스명": "노인 목욕 및 이·미용 바우처 사업 지원", "서비스목적요약": "만  65세 이상 국민기초생활수급자에게 목욕 및 이미용 지원", "지원내용": "○ 지원대상 : 만 65세 이상 국민기초생활수급자\r\n\r\n○ 지원내용 : 연간 총 18매 이용권 지급(목욕권 : 10매, 이미용권 : 8매)\r\n\r\n○ 협약 업소에서 대상자 무료로 이용", "지원대상": "○ 만 65세 이상 국민기초생활수급자", "소관기관명": "경기도 안산시", "서비스분야": "생활안정", "신청기한": "신청 불필요", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/393000000108", "지원유형": "이용권"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('508000000681', '저소득층 기초생활보장 지원', JSON '{"서비스ID": "508000000681", "서비스명": "저소득층 기초생활보장 지원", "서비스목적요약": "기초수급자 대상으로 상수도 요금 및 교복구입비 지원", "지원내용": "○ 상수도 요금 지원 : 기초생계(의료)수급자 상수도 기본요금 상당 분기별 지원\r\n\r\n○ 교복구입비 지원 : 기초생계(의료)수급자 자녀 교복 구입비 지원", "지원대상": "○ 상수도 요금 지원\r\n - 기초생계(의료)수급자 중 상수도 요금을 납부하는 자(장기입원 등에 따른 주거급여 제외자 및 시설수급자, 읍면 간이상수도 사용자 제외)\r\n\r\n○ 교복구입비 지원 \r\n - 기초생계(의료)수급자 자녀 중 중고등학교 신입생", "소관기관명": "경상북도 구미시", "서비스분야": "생활안정", "신청기한": "○ 교복구입비 지원 : 매년 2월", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/508000000681", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('321000000110', '서초구 기초생활수급자 관내 이사지원', JSON '{"서비스ID": "321000000110", "서비스명": "서초구 기초생활수급자 관내 이사지원", "서비스목적요약": "서초구 생계급여·의료급여 수급가구의 관내 이사비용 지원", "지원내용": "서초구 주민등록 중인 국민기초생활 생계 혹은 의료급여 수급가구가 이사업체 통해 서초구 내에서 이사 시 이사비용 지원(최대 20만원)\r\n  ※ 예산 조기 소진에 따른 마감 가능", "지원대상": "서초구 주민등록 중인 국민기초생활 생계 혹은 의료급여 수급가구", "소관기관명": "서울특별시 서초구", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/321000000110", "지원유형": "현금"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('323000000111', '(송파구)저소득 한부모가족 지원', JSON '{"서비스ID": "323000000111", "서비스명": "(송파구)저소득 한부모가족 지원", "서비스목적요약": "저소득한부모 가구에 명절격려금 및 김치 지원", "지원내용": "○ 관내 법정 저소득한부모가족에게 명절격려금 가구당 30,000원 지원\r\n\r\n○ 저소득 한부모 540세대 김치 한박스(15kg) 지원", "지원대상": "○ 관내 법정 저소득한부모 가구", "소관기관명": "서울특별시 송파구", "서비스분야": "생활안정", "신청기한": "신청불필요", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/323000000111", "지원유형": "현금||현물"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json) VALUES ('358000000134', '노인 보청기 지원 사업', JSON '{"서비스ID": "358000000134", "서비스명": "노인 보청기 지원 사업", "서비스목적요약": "저소득 어르신을 대상으로 보청기 지원", "지원내용": "○ 지원목적 : 난청으로 불편을 겪는 저소득 어르신에게 보청기를 지원하여 환자 중심의 의료서비스 제공\r\n\r\n○지원대상 : 관내 65세 이상 기초생활수급자, 차상위계층, 기초연금수급자 중 옹진군 1년 이상 거주자\r\n\r\n○지원내용 : - 보청기 구입비 최대 999천원\r\n                      - 후기적합비용 최대 180천원", "지원대상": "○ 65세 이상 기초생활수급자\r\n○ 65세 이상 차상위계층\r\n○ 65세 이상 기초연금 수급자 \r\n\r\n* 단, 옹진군 거주 1년이상", "소관기관명": "인천광역시 옹진군", "서비스분야": "생활안정", "신청기한": "상시신청", "상세조회URL": "https://www.gov.kr/portal/rcvfvrSvc/dtlEx/358000000134", "지원유형": "현물"}');
INSERT INTO gov24_benefit_cache (external_id, title, raw_json, min_age, max_age, min_insurance_months, min_tenure_years, is_involuntary_sub) VALUES ('CURATED-YOUTH-JOB-LEAP', '청년 일자리 도약 장려금', JSON '{"서비스명": "청년 일자리 도약 장려금", "서비스목적요약": "청년(만 15~34세)을 정규직으로 채용한 중소기업에 인건비 일부 지원", "지원내용": "채용 청년 1인당 최대 720만원(2년, 분기별 지급)", "지원대상": "만 15세~34세 청년을 정규직으로 채용한 5인 이상 우선지원대상기업", "소관기관명": "고용노동부", "서비스분야": "고용·창업", "신청기한": "채용일로부터 6개월 이내", "지원유형": "현금", "비고": "수동 검증 데이터 - 공식 상세조회URL 미확인, 운영 반영 전 work24.go.kr에서 최신 공고 재확인 필요"}', 15, 34, 0, 0, false);
